assert_pin_unique "phase 3.3: REJECT routes through the severity-aware exit (Critical still Blocks)" \
  'a REJECT whose unresolved triggers are all non-Critical' "$IMPL_SKILL"
assert_pin_unique "phase 3.3: soft-proceed records each residual finding durably in the workpad" \
  'unresolved after bounded re-review (non-Critical, surfaced for human review)' "$IMPL_SKILL"

# Drift guard: issue #193 — Phase 3.2 must triage each /simplify finding against the
# issue's in-scope ACs before applying it, skipping AC-conflicting findings with a
# recorded rationale. The OPERATIVE pin is the skip+record sentence (the behavioral fix):
# deleting it alone re-introduces the bug where AC-violating cleanups get applied silently.
# Per the behavioral-fix-pin convention (#186/#192/#194), the operative pin uses
# assert_pin_red_on_removal — the suite itself half-reverts the sentence and confirms the
# pin goes RED, baking the mutation-proof into CI rather than relying on a one-time dev check.
# The scope pin (issue-context-only) and the stale-AC carve-out pin (Phase 2.2.6, not a silent
# skip) stay assert_pin_unique presence guards — they are framing/scope, not the behavioral fix.
assert_pin_red_on_removal "phase 3.2: /simplify findings triaged — operative skip+record sentence (mutation-proven)" \
  'skip the finding and record the AC conflict as the skip rationale' "$IMPL_SKILL"
assert_pin_unique "phase 3.2: triage scoped to the issue-context /devflow:implement path only" \
  'exists only on the issue-context' "$IMPL_SKILL"
assert_pin_unique "phase 3.2: stale-AC conflict routes to Phase 2.2.6, not a silent skip" \
  'that is Phase 2.2.6 AC-rewrite territory' "$IMPL_SKILL"

# Same drift guard for the 2.3.0a peer-checkpoint-completeness sweep: the additive
# twin of 2.3.0 lives in the same three places (sweep body, "Sweep selection" index,
# rationale table) and must stay in sync. It homes the recurring incomplete-edit
# sub-pattern (a rule added at only some of its co-equal peer sites); if any of the
# three loses it, that catch reverts to a review REJECT or a post-bot fix.
assert_pin_unique "sweep 2.3.0a: implement SKILL keeps the sweep body" '#### 2.3.0a Peer-checkpoint completeness sweep' "$IMPL_SKILL"
assert_pin_unique "sweep 2.3.0a: implement SKILL lists it in the always-run index" 'run **2.3.0a**' "$IMPL_SKILL"
assert_eq "sweep 2.3.0a: docs/implement-skill.md keeps the rationale table row" "yes" \
  "$(grep -qF '| 2.3.0a Peer-checkpoint completeness |' "$IMPL_DOC" && echo yes || echo no)"
# Pin one step token unique to the 2.3.0a procedure (the grep-the-peer-set rule) so a
# reviewer who guts the steps but keeps the heading still trips the suite.
assert_pin_unique "sweep 2.3.0a: implement SKILL keeps the enumerate-by-grep step" 'Enumerate the peer set by grep, not from memory' "$IMPL_SKILL"

# Issue #165 Part C: four-mirror-site drift guard for the new 2.3.0b
# enum-enumeration reconciliation sweep — the sibling of 2.3.0a for "a value was
# added to an enumerated set". It lives in four places (sweep body, "Sweep
# selection" index, rationale table, and the DEVFLOW_SYSTEM_OVERVIEW.md sweep-list
# entry pinned below) and must stay in sync; if any loses it, the catch for a
# stale doc/comment enumeration or fall-through consumer reverts to a shadow-review
# finding or a post-bot fix.
# The three SKILL-body pins use assert_pin_unique (exactly-once), matching the 2.3.0a/2.3.6
# sibling sweep-body pins above — not the raw single-line presence form, which #157 AC2's
# repo-wide scanner flags as an un-routed raw SKILL guard. (#166 landed them in the raw form;
# this is the cross-PR reconciliation to #157's widened rule.) The IMPL_DOC / OVERVIEW mirrors
# below stay in presence form like their sibling doc-row pins — the AC2 scanner does not cover
# non-SKILL files.
assert_pin_unique "sweep 2.3.0b: implement SKILL keeps the sweep body" '#### 2.3.0b Enum-enumeration reconciliation sweep' "$IMPL_SKILL"
assert_pin_unique "sweep 2.3.0b: implement SKILL lists it in the Sweep-selection index" 'run **2.3.0b**' "$IMPL_SKILL"
assert_eq "sweep 2.3.0b: docs/implement-skill.md keeps the rationale table row" "yes" \
  "$(grep -qF '| 2.3.0b Enum-enumeration reconciliation |' "$IMPL_DOC" && echo yes || echo no)"
# Pin one step token unique to the 2.3.0b procedure (the grep-every-enumerating-site
# rule) so a reviewer who guts the steps but keeps the heading still trips the suite.
assert_pin_unique "sweep 2.3.0b: implement SKILL keeps the enumerate-every-site step" 'Enumerate every site that names a member of the set, by grep' "$IMPL_SKILL"
# Fourth mirror site (the same pinned-OVERVIEW-row idiom 2.3.0c's AC11 pin reuses below): Part C
# added a sweep-list line in docs/DEVFLOW_SYSTEM_OVERVIEW.md. This PR's own iteration-1
# review caught that line stale, proving it is a coupled mirror — so pin it too, or a
# later edit could silently drop 2.3.0b from the OVERVIEW and the suite would stay green.
assert_eq "sweep 2.3.0b: DEVFLOW_SYSTEM_OVERVIEW keeps the sweep-list entry" "yes" \
  "$(grep -qF '**2.3.0b** Enum-enumeration reconciliation sweep (added value to an enumerated set' "$LIB/../docs/DEVFLOW_SYSTEM_OVERVIEW.md" && echo yes || echo no)"

# Substrate-agnostic re-anchor (issue #171): the "Sweep selection (run first)" preamble
# must state that its trigger shapes apply to prose/SKILL/doc/config as much as to code,
# so an add-only prose/doc/config diff that replicates a peer rule, an enumerated-set
# member, or a mirrored contract literal across sites still trips the contract-completeness
# sweeps (2.3.0 / 2.3.0a / 2.3.0b) rather than falling through to "just the five always-on sweeps".
# Coupled invariant: the re-anchor lives in BOTH the SKILL preamble and its
# docs/implement-skill.md mirror, so pin BOTH sites — a one-sided revert of either back to
# the code-only framing then fails closed (the dominant convention-violation half-revert
# pattern). assert_pin_unique asserts the literal occurs EXACTLY once, so each pin goes RED
# on removal (count 0) AND on accidental duplication (count > 1) — stronger than a bare grep.
# Both literals are ASCII + apostrophe-free per the embedded-jq/SC11xx single-quote trap.
# The mutation property is proven by the assert_pin_unique removal semantics (meta-tested
# elsewhere in this suite).
assert_pin_unique "sweep selection: implement SKILL re-anchors classification on cross-site replication (substrate-agnostic)" \
  "classify by what the change replicates across sites, not by whether it is code" \
  "$IMPL_SKILL"
assert_pin_unique "sweep selection: docs/implement-skill.md mirror carries the substrate-agnostic re-anchor (coupled invariant)" \
  "so the preamble classifies by *what the change replicates across sites*, not by whether it is code" \
  "$IMPL_DOC"
# Pin the OPERATIVE qualifier too, not just the framing clause above: the behavioral fix
# is the sentence that says an add-only prose/doc/config diff still trips 2.3.0/2.3.0a/2.3.0b
# (exactly the PR #166 regression). Reverting only that qualifier back to the unconditional
# "just the five always-on sweeps" — while leaving the pinned re-anchor clause intact — is a
# half-revert that ships the regression; the framing pins above do not catch it. Pin the
# qualifier at BOTH coupled sites so that half-revert fails closed.
assert_pin_unique "sweep selection: implement SKILL qualifies the five-always-on sentence so a replicating prose/doc/config diff still trips the contract sweeps" \
  "still trips the contract-completeness sweeps (**2.3.0** / **2.3.0a** / **2.3.0b**), not just the five" \
  "$IMPL_SKILL"
assert_pin_unique "sweep selection: docs/implement-skill.md mirror qualifies the five-always-on sentence (coupled invariant)" \
  "still runs the contract-completeness sweeps (2.3.0 / 2.3.0a / 2.3.0b)" \
  "$IMPL_DOC"
# Cross-site enumeration check: both sites must name the SAME contract-sweep set.
# Each per-site pin above only checks its own local literal — a site could silently
# drop 2.3.0b while the other keeps it and both pins still pass. Extract the sweep
# IDs (strip markdown bold markers) from each qualifying sentence and assert equality.
_skill_sweeps=$(grep -oE 'still trips the contract-completeness sweeps \([^)]+\)' "$IMPL_SKILL" \
  | grep -oE '[0-9]+\.[0-9]+\.[0-9]+[a-z]*' | sort | tr '\n' ' ' | sed 's/ $//')
_docs_sweeps=$(grep -oE 'still runs the contract-completeness sweeps \([^)]+\)' "$IMPL_DOC" \
  | grep -oE '[0-9]+\.[0-9]+\.[0-9]+[a-z]*' | sort | tr '\n' ' ' | sed 's/ $//')
assert_eq "sweep selection: SKILL and docs enumerate the same contract-sweep set (cross-site)" \
  "$_skill_sweeps" "$_docs_sweeps"

# ── issue #474: Phase 2.3 gains §2.3.7 (collection-cardinality sweep) and two §2.3.0c
# sharpenings (derived-comparand arms, obligation placement). Each BEHAVIORAL pin below
# (the assert_pin_red_under calls) targets the OPERATIVE sentence — the minimal text whose
# removal ALONE re-introduces the guarded gap — with a `sed -E` mutation that removes only
# that sentence, so a framing-only pin would be reported RED (per the behavioral-fix-pin
# rule). The behavioral pins scope to phase-2-implement.md ($P2_FILE); the docs/overview
# mirror-presence pins (assert_pin_unique / assert_eq) and the reconciliation guards
# (assert_eq) guard the coupled enumerating sites (§2.3.0b enumeration reconciliation).
OVERVIEW_DOC474="$LIB/../docs/DEVFLOW_SYSTEM_OVERVIEW.md"
# §2.3.0c trigger (a): a DERIVED comparand's malformed/empty arms must be enumerated. The
# operative requirement, the arm list, and the defect teeth are three necessary sentences —
# one pin each (a multi-sentence property under-covers with a single pin).
assert_pin_red_under "#474(2.3.0c-a): derived-comparand arm-enumeration requirement is operative" \
  'its row additionally enumerates the malformed/empty arms the producer can emit' \
  's|its row additionally enumerates the malformed/empty arms the producer can emit|its row is otherwise complete|' "$P2_FILE"
assert_pin_red_under "#474(2.3.0c-a): the six-shape arm list is operative (removing it re-opens the unenumerated-arm gap)" \
  'producer failure (a non-zero exit or a denial), unparseable output, a wrong-type value, a valid-falsy/empty value, and a missing key or file' \
  's|producer failure \(a non-zero exit or a denial\), unparseable output, a wrong-type value, a valid-falsy/empty value, and a missing key or file|the arms|' "$P2_FILE"
assert_pin_red_under "#474(2.3.0c-a): the unenumerated-arm defect teeth are operative (removing the whole this-PR-defect obligation, not just its adjective, re-opens the gap)" \
  'is an unauthored fail-open accident and a defect in **this** PR' \
  's|is an unauthored fail-open accident and a defect in \*\*this\*\* PR|is acceptable|' "$P2_FILE"
# §2.3.0c trigger (b): a stated policy places its obligation at the execution point it gates.
assert_pin_red_under "#474(2.3.0c-b): obligation-placement requirement is operative" \
  'A stated policy places its obligation at the execution point it gates' \
  's|A stated policy places its obligation at the execution point it gates|A policy may be stated anywhere|' "$P2_FILE"
assert_pin_red_under "#474(2.3.0c-b): thematic-only prose does not discharge the trigger (teeth are operative)" \
  'prose that describes the hazard only in a thematic section, leaving the execution point it gates with no obligation, does not discharge this trigger' \
  's|prose that describes the hazard only in a thematic section, leaving the execution point it gates with no obligation, does not discharge this trigger|thematic-only prose is fine|' "$P2_FILE"
# §2.3.7 collection-cardinality sweep: heading trigger, multi-element requirement,
# single-element-non-discharge teeth, and the Sweep-selection index row.
assert_pin_red_under "#474(2.3.7): the heading trigger is operative (removing it un-gates the sweep)" \
  'mandatory whenever the change adds a collection output with ordering, dedup, or aggregation logic' \
  's|mandatory whenever the change adds a collection output with ordering, dedup, or aggregation logic|always|' "$P2_FILE"
assert_pin_red_under "#474(2.3.7): the multi-element test requirement is operative" \
  'The change carries a multi-element test case that exercises that logic' \
  's|The change carries a multi-element test case that exercises that logic|A test exists|' "$P2_FILE"
assert_pin_red_under "#474(2.3.7): single-element-does-not-discharge teeth are operative" \
  'A single-element happy-path test does not discharge this sweep' \
  's|A single-element happy-path test does not discharge this sweep|A single-element test suffices|' "$P2_FILE"
assert_pin_red_under "#474(2.3.7): the Sweep-selection consider-list index row is operative" \
  'Adds a collection output with ordering, dedup, or aggregation logic' \
  's|Adds a collection output with ordering, dedup, or aggregation logic|Adds something|' "$P2_FILE"
# §2.3.7 step 3 is the self-referential arm — DevFlow's own deliverable is prose, so the
# un-drivable-output branch (dry-trace over >=2 elements incl. a duplicate) governs how the
# sweep applies to this very repo. Pin its operative multi-element requirement so a future
# edit cannot weaken it to a single-element/"an example" trace without going RED.
assert_pin_red_under "#474(2.3.7): the un-drivable-output dry-trace multi-element requirement is operative" \
  'against at least two elements including a duplicate, never a single-element trace' \
  's|against at least two elements including a duplicate, never a single-element trace|against an example|' "$P2_FILE"
# §2.3.0c COMPLETION-GATE appended clauses (PR #481 review, finding a): the completion-gate
# sentence begins with the prefix the #376 w2-completion-gate pin already pins ("The sweep is
# not done until every comparand has a completed four-column row"), but #474 APPENDED two
# clauses that bind the gate to the two new triggers — trigger-a's derived-arm enumeration and
# trigger-b's obligation-placement. The #376 mutation removes only the unchanged prefix, and the
# 2.3.0c-a/2.3.0c-b definition pins target the DEFINITION sentences (different wording), so
# dropping either appended gate clause left every existing pin GREEN. Pin each appended clause
# with a mutation that WEAKENS the gate (drops the requirement) → a future edit that guts the
# gate-level obligation while leaving the definitions intact goes RED here. (Mutations use `.`
# to match the ASCII apostrophe in comparand's/arm's so the sed program stays single-quote-safe.)
assert_pin_red_under "#474(2.3.0c-a): the completion gate binds trigger-a derived-arm enumeration (appended clause, distinct from the #376 prefix pin)" \
  'malformed/empty arms enumerated and each arm' \
  's|with a derived comparand.s malformed/empty arms enumerated and each arm.s decided behavior stated \(trigger a\)|with each comparand row present|' "$P2_FILE"
assert_pin_red_under "#474(2.3.0c-b): the completion gate binds trigger-b obligation-placement (appended clause, distinct from the #376 prefix pin)" \
  'places that obligation at the execution point it gates (trigger b)' \
  's|, and places that obligation at the execution point it gates \(trigger b\)||' "$P2_FILE"
# §2.3.7 closing ENFORCEMENT sentence (PR #481 review, finding b): the "defect in **this** PR,
# not a downstream finding" teeth are what make the sweep a mandatory this-PR obligation rather
# than advisory guidance; none of the §2.3.7 pins above cover this sentence, so softening it
# from mandatory to advisory flipped no pin RED. The mutation rewrites the mandatory framing
# into an accept-and-defer framing, removing the pinned "defect in **this** PR" teeth → RED.
assert_pin_red_under "#474(2.3.7): the closing this-PR-defect enforcement sentence is operative (softening mandatory->advisory goes RED)" \
  'shipped with only a single-element test as a defect in **this** PR' \
  's|as a defect in \*\*this\*\* PR, not a|as acceptable to defer to a|' "$P2_FILE"
# §2.3.7 mirror sites (coupled invariant — the enumerating sites §2.3.0b reconciliation
# requires): the sweep body heading, the Sweep-selection index row, the docs rationale
# table row, and the DEVFLOW_SYSTEM_OVERVIEW sweep-index entry must all carry §2.3.7.
assert_pin_unique "#474(2.3.7): implement SKILL keeps the sweep body heading" \
  '#### 2.3.7 Collection-cardinality sweep' "$IMPL_SKILL"
assert_pin_unique "#474(2.3.7): implement SKILL lists it in the Sweep-selection index" \
  'run **2.3.7**' "$IMPL_SKILL"
assert_eq "#474(2.3.7): docs/implement-skill.md keeps the rationale table row" "yes" \
  "$(grep -qF '| 2.3.7 Collection-cardinality |' "$IMPL_DOC" && echo yes || echo no)"
assert_eq "#474(2.3.7): DEVFLOW_SYSTEM_OVERVIEW keeps the sweep-index entry" "yes" \
  "$(grep -qF '**2.3.7** Collection-cardinality sweep' "$OVERVIEW_DOC474" && echo yes || echo no)"
# Reconciliation guards: the falsified "2.3.6 is last" claims must be GONE from the docs
# (a regression would re-assert a §2.3.7-falsified statement), and the "five always-on
# sweeps (…)" enumeration must be UNCHANGED (§2.3.7 is trigger-gated, never always-on).
# Each absence guard is paired with an INJECTION non-vacuity proof (the #465 delta form,
# 7f7161a): an absolute `== 0` alone cannot tell "phrase removed" from "grep blind", so it
# would degrade to a no-op if the phrase were reworded. Inject the phrase into a copy and
# confirm the SAME grep detects it (count rises by exactly 1) — proving the `0` is a
# reconciled body, not a blind detector. Injection (not a base-ref read) keeps the proof
# robust to merge state: origin/main carries the reconciled body once this PR merges.
for _474_ABSENT in 'numbered last only to avoid renumbering' '2.3.6 sits last'; do
  assert_eq "#474: docs no longer claim '$_474_ABSENT' (§2.3.7-falsified 'last' claim reconciled)" "0" \
    "$(grep -Fc "$_474_ABSENT" "$IMPL_DOC")"
  _474_INJ="$(probe_tmp "#474 absence-guard injection: '$_474_ABSENT'")" || continue
  { cat "$IMPL_DOC"; printf '%s (injected)\n' "$_474_ABSENT"; } > "$_474_INJ"
  assert_eq "#474: absence guard non-vacuous — injecting '$_474_ABSENT' raises the count by 1" \
    "$(( $(grep -Fc "$_474_ABSENT" "$IMPL_DOC") + 1 ))" "$(grep -Fc "$_474_ABSENT" "$_474_INJ")"
  rm -f "$_474_INJ"
done
assert_eq "#474: the five-always-on enumeration is unchanged (2.3.7 is trigger-gated, not always-on)" "yes" \
  "$(grep -qF 'five always-on sweeps (2.3.3/2.3.4/2.3.4a/2.3.5/2.3.6)' "$IMPL_DOC" && echo yes || echo no)"

# Drift guard: the base_branch read in the implement skill (phases/phase-1-setup.md) Phase 1.4 is
# a load-bearing inline-bash block in the skill (Phase 3.1's §3.1 re-derivation below is another) — like the max_iterations clamp above, the
# tokens it relies on can be silently broken by a SKILL edit (drop the `|| BASE=""`
# and `git fetch origin ""` runs; drop the fetch guard and a bad base fails with a
# bare git error instead of an attributable DevFlow breadcrumb). Pin the tokens so
# a refactor of the block fails here rather than shipping a silent regression.
# NOTE: the two read+guard literals below (`config-get.sh .base_branch main` and
# `[ -n "$BASE" ]`) now ALSO appear in phases/phase-3-review.md §3.1, which re-derives
# BASE before `gh pr create` (issue #224). So these two pins are scoped to the
# phase-1-setup.md file (where Phase 1.4 lives) rather than the whole bundle, keeping
# them unique-per-file; the phase-3 re-derivation has its own pins further below.
assert_pin_unique "base_branch read: Phase 1.4 reads via config-get with the main default" 'config-get.sh .base_branch main' "$IMPL_PHASES_DIR/phase-1-setup.md"
assert_pin_unique "base_branch read: Phase 1.4 guards the empty read" '[ -n "$BASE" ]' "$IMPL_PHASES_DIR/phase-1-setup.md"
# Scoped to phase-1-setup.md (Phase 1.4's fetches): issue #284 added a SECOND
# `git fetch origin "$BASE"` in phase-4-documentation.md's Stage-2 diff-gate retry, so a
# bundle-wide unique pin double-matches — the Phase 1.4 fetches live in phase-1-setup.md.
# Issue #429 added the adopted-branch (USE_CURRENT) arm's freshness fetch, so phase-1-setup.md
# now carries TWO `git fetch origin "$BASE"` sites (the new-branch create arm AND the adopted
# arm), and the pin asserts BOTH are present rather than a single unique one — both arms fetch
# the base, so no adopted run reads a stale fork point (the #325 guard).
assert_eq "base_branch read: SKILL fetches origin/\$BASE on both the create and adopted arms (not hard-coded main)" "2" \
  "$(grep -cF 'git fetch origin "$BASE"' "$IMPL_PHASES_DIR/phase-1-setup.md" || true)"
assert_pin_unique "base_branch read: SKILL checks out origin/\$BASE" 'git checkout -b "$BRANCH" "origin/$BASE"' "$IMPL_SKILL"
assert_pin_unique "base_branch read: SKILL keeps the attributable fetch-failure breadcrumb" 'could not fetch base branch' "$IMPL_SKILL"
assert_pin_unique "#168 create-path: SKILL guards branch-for-issue.py exit status" \
  'branch-for-issue.py failed' "$IMPL_SKILL"
assert_pin_unique "#168 create-path: SKILL guards against an empty BRANCH name" \
  '[ -n "$BRANCH" ]' "$IMPL_SKILL"

# Issue #224: Phase 3.1 (phases/phase-3-review.md) opens the draft PR against the
# CONFIGURED base_branch, not the GitHub default branch. Because each phase's bash
# block is a SEPARATE shell, Phase 1.4's $BASE is out of scope at 3.1, so 3.1 must
# RE-DERIVE it (same config-get read + fail-closed guard) and pass --base "$BASE" to
# `gh pr create`. Pin both halves against the phase-3 file specifically: dropping the
# --base flag OR the re-derivation guard turns the suite RED (the operand-traceability
# pin ensures the --base pin can't pass with an empty $BASE — the exact bug class).
P3_REVIEW="$IMPL_PHASES_DIR/phase-3-review.md"
# Include the leading `create ` so the pinned literal does not start with `--`
# (pin_count's `grep -oF` would otherwise parse a `--base…` pattern as grep options
# and match nothing): this pins the flag ON the `gh pr create` invocation specifically.
assert_pin_unique "#224 Phase 3.1: gh pr create passes --base \"\$BASE\"" 'create --base "$BASE"' "$P3_REVIEW"
assert_pin_unique "#224 Phase 3.1: re-derives BASE via config-get with the main default" 'config-get.sh .base_branch main' "$P3_REVIEW"
assert_pin_unique "#224 Phase 3.1: re-derives BASE with the fail-closed empty-read guard" '[ -n "$BASE" ]' "$P3_REVIEW"
# The guard PREDICATE `[ -n "$BASE" ]` is only half the fail-closed contract; its
# CONSEQUENT — the `BASE=main` fallback assignment — is what actually keeps `--base`
# from going out empty. Pin it too: a refactor that keeps the predicate but drops the
# `|| { …; BASE=main; }` action would ship `gh pr create --base ""` (the silent
# mistarget this PR exists to prevent) while every predicate/ordering pin stayed GREEN.
assert_pin_unique "#224 Phase 3.1: empty-read guard falls back to main (fail-closed consequent)" 'BASE=main' "$P3_REVIEW"
# Ordering/same-block guard (issue #224 iter 2): the pins above prove the tokens EXIST
# but are positionally independent — a refactor that put `gh pr create --base "$BASE"`
# BEFORE the re-derivation, or split them into separate ```bash fences, would leave them
# all GREEN while $BASE is empty/unset at create time: the exact shell-boundary
# mistarget (`--base ""`) §3.1's prose forbids. Assert the full producer→guard→fallback
# →consumer order WITHIN ONE fenced bash block: the producer (config-get read `d`), the
# fail-closed empty-read guard `[ -n "$BASE" ]` (`g`), AND its `BASE=main` fallback
# action (`f`) all precede the consumer `gh pr create --base "$BASE"` (`c`), in the order
# d < g < f < c. Pinning the fallback action's position too (not just the predicate's)
# catches a refactor that relocates the guard OR drops the fallback action out of the
# create-block — the "guard whose comparand can be absent fails open" class CLAUDE.md
# flags. RED if reordered, split across blocks, or the guard/fallback is moved out of /
# after the create.
assert_eq "#224 Phase 3.1: re-derivation + empty-read guard + main-fallback precede gh pr create in the SAME bash block" "yes" \
  "$(python3 -c '
import sys, re
t = open(sys.argv[1]).read()
ok = "no"
for m in re.finditer(r"```bash\n(.*?)```", t, re.S):
    b = m.group(1)
    if "gh pr create --base \"$BASE\"" in b:
        d = b.find("config-get.sh .base_branch main")
        g = b.find("[ -n \"$BASE\" ]")
        f = b.find("BASE=main")
        c = b.find("gh pr create --base \"$BASE\"")
        if -1 not in (d, g, f, c) and d < g < f < c:
            ok = "yes"
        break
print(ok)
' "$P3_REVIEW")"
# Deferred (issue #224 review, Suggestion): we do NOT pin that §3.1 OMITS --head.
# Low value — `gh pr create` defaults --head to the checked-out branch, which is the
# correct feature branch at Phase 3.1; a future edit adding --head would not corrupt
# the base targeting this fix protects. Revisit only if --head is ever passed here.

# Versioning is per-repo policy, not the engine's job: implement/SKILL.md must carry NO
# version-bump step. A repo that wants version management opts in via its consumer prompt
# extension (.devflow/prompt-extensions/implement.md), which the loader appends to the skill.
# Pin (1) both removed section headings to 0, (2) no stray Phase-2.6/3.1.5 cross-refs, and
# (3) that DevFlow itself re-homes its own rule into that extension so the dogfooded behavior
# is not silently lost. ("Step 2.6" refs elsewhere belong to review-and-fix, not here.)
assert_eq "implement: no version-bump section (versioning is per-repo, not the engine)" "0" \
  "$(grep -cE '^### (2\.6 Version & changelog|3\.1\.5 Apply the version bump)' "$IMPL_SKILL")"
assert_eq "implement: no stray version-phase cross-refs (Phase 2.6 / 3.1.5)" "0" \
  "$(grep -cE '3\.1\.5|Phase 2\.6' "$IMPL_SKILL")"
assert_eq "implement: DevFlow re-homes its versioning rule to the implement prompt extension" "yes" \
  "$(EXT="$LIB/../.devflow/prompt-extensions/implement.md"; [ -s "$EXT" ] && grep -qF 'plugin.json' "$EXT" && grep -qiF 'changelog' "$EXT" && echo yes || echo no)"

# Behavioral coverage for the base_branch read+guard (token pins above catch a
# refactor that DROPS a token, but not a semantic regression in config-get's
# soft/hard contract that the guard depends on). Mirrors the max_iterations
# resolver+clamp pattern: exercise config-get's real exit behavior, then the
# SKILL's inline guard logic against it. Keep byte-aligned with the SKILL block.
BB_CFG="$(mktemp)"
printf '%s' '{"base_branch":"develop"}' > "$BB_CFG"
assert_eq "base_branch: configured value read back verbatim" "develop" \
  "$("$CG" .base_branch main "$BB_CFG")"
printf '%s' '{"devflow":{"effort":"high"}}' > "$BB_CFG"
assert_eq "base_branch: absent key → resolver soft-defaults to main (exit 0)" "main" \
  "$("$CG" .base_branch main "$BB_CFG")"
assert_eq "base_branch: missing config file → resolver soft-defaults to main (exit 0)" "main" \
  "$("$CG" .base_branch main /no/such/config.json)"
# Hard path: a malformed config must exit NON-ZERO with EMPTY stdout (the default is
# NOT applied) — this is the exact contract the inline guard relies on. A regression
# that made config-get emit `main` here would silently mask a malformed-config repo
# onto main; this assertion fails loudly if that contract ever drifts.
printf '%s' '{bad json' > "$BB_CFG"
BB_OUT="$("$CG" .base_branch main "$BB_CFG" 2>/dev/null)"; BB_RC=$?
assert_eq "base_branch: malformed config → resolver exits non-zero, empty stdout" "nonzero-empty" \
  "$([ "$BB_RC" -ne 0 ] && [ -z "$BB_OUT" ] && echo nonzero-empty || echo "rc=$BB_RC out='$BB_OUT'")"
rm -f "$BB_CFG"

# The SKILL's inline empty-read guard (Phase 1.4): an empty OR failed read → 'main'.
# Mirrors `BASE=$(config-get.sh …) || BASE=""; [ -n "$BASE" ] || BASE=main` so the
# fallback is exercised as behavior, not just asserted as text.
base_guard() {
  local v="$1" rc="${2:-0}"
  { [ "$rc" -eq 0 ] && [ -n "$v" ]; } && { printf '%s\n' "$v"; return; }
  printf 'main\n'
}
assert_eq "base_branch guard: configured value honored"            "develop" "$(base_guard develop)"
assert_eq "base_branch guard: empty read (rc 0) → main"            "main"    "$(base_guard '')"
assert_eq "base_branch guard: hard-failure read (rc≠0, empty) → main" "main" "$(base_guard '' 2)"

# Worktree-branch detection (#168): Phase 1.4 must reuse the branch a linked git
# worktree was pre-created on (whatever its name) instead of creating a SECOND
# branch. The signal is naming-independent — a linked worktree's --git-common-dir
# (the main repo's .git) differs from its --git-dir (.git/worktrees/<name>); in the
# main working tree they are equal. Token pins so a SKILL refactor that drops the
# mechanism fails HERE rather than silently regressing to a second branch.
assert_pin_unique "#168 worktree detect: SKILL captures CUR via git branch --show-current" \
  'CUR=$(git branch --show-current 2>/dev/null) || CUR=""' "$IMPL_SKILL"
assert_pin_unique "#168 worktree detect: SKILL reads --git-common-dir in absolute form" \
  'git rev-parse --path-format=absolute --git-common-dir' "$IMPL_SKILL"
assert_pin_unique "#168 worktree detect: SKILL reads --git-dir in absolute form" \
  'git rev-parse --path-format=absolute --git-dir' "$IMPL_SKILL"
assert_pin_unique "#168 worktree detect: SKILL guards reuse against the base branch (never builds on trunk)" \
  '"$CUR" != "$BASE"' "$IMPL_SKILL"
# The base/detached-HEAD guard must wrap BOTH reuse signals (Signal 2's name match too),
# so a base branch named like a feature branch (base_branch=issue-next) still CREATEs.
# Pin the breadcrumb so the silent-degrade path stays attributable.
# Wording covers both symmetric (both-empty) and asymmetric (one-empty) trigger cases.
assert_pin_unique "#168 worktree detect: SKILL leaves a breadcrumb when git-dir paths are empty" \
  'one or both git-dir path values are empty' "$IMPL_SKILL"
assert_pin_unique "#168 worktree detect: SKILL breadcrumb names asymmetric env-override as a cause" \
  'injected GIT_DIR/GIT_COMMON_DIR env override' "$IMPL_SKILL"
assert_pin_unique "#168 create-path: SKILL gates create block on USE_CURRENT being unset" \
  '[ -z "$USE_CURRENT" ]' "$IMPL_SKILL"
assert_eq "#168 worktree detect: SKILL names the linked-worktree signal" "yes" \
  "$(grep -qF 'linked worktree' "$IMPL_SKILL" && echo yes || echo no)"  # raw-guard-ok: non-unique: token appears in both prose and code (4 occurrences)
assert_pin_unique "#168 worktree detect: SKILL keeps the cloud-tier name match as a second skip condition" \
  'claude/issue-*|issue-*) USE_CURRENT=1' "$IMPL_SKILL"

# Behavioral coverage: mirror Phase 1.4's reuse-vs-create decision and exercise the
# whole matrix. Keep behaviorally aligned with the SKILL block (it is a restructured
# mirror — early-return form — not a byte-for-byte copy). Echoes "reuse" (skip creation,
# use CUR) or "create" (fall through to branch-for-issue.py). The non-empty + != base
# guards wrap BOTH signals exactly as the SKILL hoists them; an empty common==gitdir
# (rev-parse failed) collapses Signal 1 to "not a worktree" → create (fail-closed).
# Source of truth: SKILL Phase 1.4 (F-8 deferred: token pins catch removal but not a
# predicate-shape change; F-9 deferred: --path-format=absolute normalization is not
# exercised here — the mirror receives pre-resolved strings; a real-git integration test
# would be needed to cover the rev-parse call itself).
#   decide_branch <git-common-dir> <git-dir> <CUR> <BASE>
decide_branch() {
  local common="$1" gitdir="$2" cur="$3" base="$4"
  # Guards apply to BOTH reuse signals: never reuse a detached HEAD (empty CUR) or the
  # base branch (build on trunk), regardless of which signal would otherwise match.
  if [ -n "$cur" ] && [ "$cur" != "$base" ]; then
    # Signal 1 — linked worktree: common-dir != git-dir (both absolute, both non-empty).
    [ -n "$common" ] && [ -n "$gitdir" ] && [ "$common" != "$gitdir" ] && { echo reuse; return; }
    # Signal 2 — cloud-tier name match (GitHub Action path; not a worktree).
    case "$cur" in
      claude/issue-*|issue-*) echo reuse; return ;;
    esac
  fi
  echo create
}
# AC1+AC2: in a linked worktree, a harness branch whose name matches NEITHER pattern
# is still reused via the worktree signal — exactly the case that used to create a
# second branch.
assert_eq "#168 worktree detect: worktree + worktree-issue-165 (name matches neither) → reuse" "reuse" \
  "$(decide_branch /repo/.git /repo/.git/worktrees/issue-165 worktree-issue-165 main)"
# Overlap: worktree AND a name-matching branch (both signals true) → reuse (locks the
# both-true path so a future refactor can't make the signals mutually exclusive).
assert_eq "#168 worktree detect: worktree + issue-9 (both signals true) → reuse" "reuse" \
  "$(decide_branch /repo/.git /repo/.git/worktrees/x issue-9 main)"
# AC3: cloud-tier name detection still skips creation, in the main working tree (no worktree).
assert_eq "#168 worktree detect: main tree + issue-5 → reuse (name match)" "reuse" \
  "$(decide_branch /repo/.git /repo/.git issue-5 main)"
assert_eq "#168 worktree detect: main tree + claude/issue-5 → reuse (name match)" "reuse" \
  "$(decide_branch /repo/.git /repo/.git claude/issue-5 main)"
# AC4 (fail-closed): inside a worktree but ON the base branch → CREATE, never reuse —
# the change must never build directly on trunk.
assert_eq "#168 worktree detect: worktree + base branch (main) → create [fail-closed]" "create" \
  "$(decide_branch /repo/.git /repo/.git/worktrees/x main main)"
assert_eq "#168 worktree detect: worktree + base branch (develop) → create [fail-closed]" "create" \
  "$(decide_branch /repo/.git /repo/.git/worktrees/x develop develop)"
# AC4 (peer completeness): the base guard wraps Signal 2 too — a base branch NAMED like a
# feature branch (base_branch=issue-5) must still CREATE, not reuse via the name match,
# in the main tree AND inside a worktree.
assert_eq "#168 worktree detect: main tree + base named issue-5 (CUR==BASE) → create [fail-closed]" "create" \
  "$(decide_branch /repo/.git /repo/.git issue-5 issue-5)"
assert_eq "#168 worktree detect: worktree + base named issue-5 (CUR==BASE) → create [fail-closed]" "create" \
  "$(decide_branch /repo/.git /repo/.git/worktrees/x issue-5 issue-5)"
# Fail-closed: detached HEAD inside a worktree (empty CUR) → CREATE, never reuse an empty branch.
assert_eq "#168 worktree detect: worktree + detached HEAD (empty CUR) → create [fail-closed]" "create" \
  "$(decide_branch /repo/.git /repo/.git/worktrees/x '' main)"
# Fail-closed: git rev-parse FAILED (empty common == empty gitdir) → Signal 1 collapses
# to "not a worktree"; a non-matching name then CREATEs (with the SKILL breadcrumb).
assert_eq "#168 worktree detect: rev-parse failure (empty dirs) + worktree-issue-165 → create [fail-closed]" "create" \
  "$(decide_branch '' '' worktree-issue-165 main)"
# Asymmetric rev-parse (one empty, one populated — injected GIT_DIR or transient failure)
# must also create, not false-positive-reuse via Signal 1 (the != inequality is vacuously
# true when one operand is empty; the non-empty guard closes this).
assert_eq "#168 worktree detect: asymmetric rev-parse (common empty, gitdir set) → create [fail-closed]" "create" \
  "$(decide_branch '' '/repo/.git/worktrees/x' worktree-issue-165 main)"
assert_eq "#168 worktree detect: asymmetric rev-parse (common set, gitdir empty) → create [fail-closed]" "create" \
  "$(decide_branch '/repo/.git' '' worktree-issue-165 main)"
# AC5: not in a worktree and not a recognized feature branch → CREATE (branch-for-issue.py path).
assert_eq "#168 worktree detect: main tree + feature-x (no worktree, no name match) → create" "create" \
  "$(decide_branch /repo/.git /repo/.git feature-x main)"
assert_eq "#168 worktree detect: main tree + base branch → create" "create" \
  "$(decide_branch /repo/.git /repo/.git main main)"

# ────────────────────────────────────────────────────────────────────────────
echo "devflow_implement.implement_pr_state (schema + resolution + Phase 4.3 gate)"
# ────────────────────────────────────────────────────────────────────────────
# implement_pr_state gates whether /devflow:implement Phase 4.3 publishes the PR
# (runs `gh pr ready`) or leaves it the draft created in Phase 3.1. The resolution
# boundary is config-get.sh (a deterministic string), so it is unit-testable here;
# the Phase 4.3 prose change (whether `gh pr ready` runs) is non-executable skill
# instructions, pinned below by token + an executable publish-decision guard that
# mirrors the SKILL's single literal-`draft` comparison. Default-to-publish is the
# safe direction: only the exact literal `draft` suppresses publishing.
IPS_SCHEMA="$LIB/../.devflow/config.schema.json"
IPS_EXAMPLE="$LIB/../.devflow/config.example.json"
IPS_PROP='.properties.devflow_implement.properties.implement_pr_state'
assert_eq "implement_pr_state: schema type is string" "string" \
  "$(jq -r "$IPS_PROP.type" "$IPS_SCHEMA")"
assert_eq "implement_pr_state: schema enum is [ready_for_review, draft]" "ready_for_review,draft" \
  "$(jq -r "$IPS_PROP.enum | join(\",\")" "$IPS_SCHEMA")"
assert_eq "implement_pr_state: schema default is ready_for_review" "ready_for_review" \
  "$(jq -r "$IPS_PROP.default" "$IPS_SCHEMA")"
assert_eq "implement_pr_state: schema has a non-empty description" "yes" \
  "$(jq -e "$IPS_PROP.description | type == \"string\" and (length > 0)" "$IPS_SCHEMA" >/dev/null && echo yes || echo no)"
assert_eq "implement_pr_state: example value matches schema default" \
  "$(jq -r "$IPS_PROP.default" "$IPS_SCHEMA")" \
  "$(jq -r '.devflow_implement.implement_pr_state' "$IPS_EXAMPLE")"

# Resolver-read behavior (the string the SKILL's Phase 4.3 reads). config-get maps an
# absent key OR an empty-string value to the supplied default (ready_for_review); any
# other value is returned verbatim and the SKILL treats non-`draft` as publish.
IPS_CFG="$(mktemp)"
printf '%s' '{"devflow_implement":{"implement_pr_state":"draft"}}' > "$IPS_CFG"
assert_eq "implement_pr_state: configured 'draft' read back verbatim" "draft" \
  "$("$CG" .devflow_implement.implement_pr_state ready_for_review "$IPS_CFG")"
printf '%s' '{"devflow_implement":{"implement_pr_state":"ready_for_review"}}' > "$IPS_CFG"
assert_eq "implement_pr_state: configured 'ready_for_review' read back verbatim" "ready_for_review" \
  "$("$CG" .devflow_implement.implement_pr_state ready_for_review "$IPS_CFG")"
printf '%s' '{"devflow_implement":{}}' > "$IPS_CFG"
assert_eq "implement_pr_state: absent key → resolver default ready_for_review" "ready_for_review" \
  "$("$CG" .devflow_implement.implement_pr_state ready_for_review "$IPS_CFG")"
printf '%s' '{"devflow_implement":{"implement_pr_state":""}}' > "$IPS_CFG"
assert_eq "implement_pr_state: empty-string value → resolver default ready_for_review" "ready_for_review" \
  "$("$CG" .devflow_implement.implement_pr_state ready_for_review "$IPS_CFG")"
printf '%s' '{"devflow_implement":{"implement_pr_state":"published"}}' > "$IPS_CFG"
assert_eq "implement_pr_state: unrecognized value read back verbatim (SKILL treats as publish)" "published" \
  "$("$CG" .devflow_implement.implement_pr_state ready_for_review "$IPS_CFG")"
assert_eq "implement_pr_state: missing config file → resolver default ready_for_review" "ready_for_review" \
  "$("$CG" .devflow_implement.implement_pr_state ready_for_review /no/such/config.json)"
# Hard read failure (malformed JSON): config-get exits NON-zero with EMPTY stdout — the
# exact contract the SKILL's `PR_STATE=$(…) || PR_STATE=ready_for_review` fallback leans
# on. This is the headline safety property (default-to-publish on a corrupt config); pin
# the resolver half here and the end-to-end half in the guard below.
printf '%s' '{bad json' > "$IPS_CFG"
IPS_OUT="$("$CG" .devflow_implement.implement_pr_state ready_for_review "$IPS_CFG" 2>/dev/null)"; IPS_RC=$?
assert_eq "implement_pr_state: malformed config → resolver exits non-zero, empty stdout" "nonzero-empty" \
  "$([ "$IPS_RC" -ne 0 ] && [ -z "$IPS_OUT" ] && echo nonzero-empty || echo "rc=$IPS_RC out='$IPS_OUT'")"
rm -f "$IPS_CFG"

# SKILL Phase 4.3 token pins: the gate is one piece of load-bearing inline bash in
# the implement skill (phases/phase-4-documentation.md). Pin the tokens so a refactor that drops them fails here rather
# than silently always-publishing (or always-drafting).
assert_pin_unique "implement_pr_state: SKILL reads via config-get with the ready_for_review default" 'config-get.sh .devflow_implement.implement_pr_state ready_for_review' "$IMPL_SKILL"
assert_pin_unique "implement_pr_state: SKILL gates publish on the literal draft" '[ "$PR_STATE" = "draft" ]' "$IMPL_SKILL"
# Pin the *command* form, not the bare token: a plain `grep -qF 'gh pr ready'` is also
# satisfied by the draft-branch diagnostic echo and the explanatory prose, so it would
# stay green even if the actual publish invocation were deleted. Pin the guarded
# `elif gh pr ready; then` so this asserts the publish command itself survives.
assert_pin_unique "implement_pr_state: SKILL keeps the guarded publish invocation (elif gh pr ready)" 'elif gh pr ready; then' "$IMPL_SKILL"
assert_pin_unique "implement_pr_state: SKILL keeps the clean-tree backstop above the gate" 'git status --porcelain' "$IMPL_SKILL"
assert_pin_unique "implement_pr_state: SKILL has draft-aware finalize wording" 'left as draft' "$IMPL_SKILL"

# Executable publish-decision guard — logic-equivalent to the SKILL's single literal-`draft`
# comparison (semantically mirrors `[ "$PR_STATE" = "draft" ]`; `$1` stands in for
# `$PR_STATE`) so the dry-trace matrix {draft, ready_for_review, "", published} is
# exercised as behavior, not just asserted as prose (the absent/default row is the
# resolver matrix above feeding `ready_for_review` into this guard; the publish arm's
# success/failure split is modeled separately by `ips_outcome` below).
ips_publishes() {
  [ "$1" = "draft" ] && { printf 'draft\n'; return; }
  printf 'publish\n'
}
assert_eq "implement_pr_state gate: 'draft' → leave draft"             "draft"   "$(ips_publishes draft)"
assert_eq "implement_pr_state gate: 'ready_for_review' → publish"      "publish" "$(ips_publishes ready_for_review)"
assert_eq "implement_pr_state gate: empty string → publish"           "publish" "$(ips_publishes '')"
assert_eq "implement_pr_state gate: unrecognized 'published' → publish" "publish" "$(ips_publishes published)"

# End-to-end read+guard, mirroring the SKILL's full Phase 4.3 line
# `PR_STATE=$(config-get … ready_for_review) || PR_STATE=ready_for_review` then the
# literal-`draft` decision. This exercises the load-bearing safety property — a hard
# resolver failure (malformed config) falls back to PUBLISH — through the real resolver,
# which the `ips_publishes` matrix alone does not cover.
ips_state_decision() {
  local st
  st="$("$CG" .devflow_implement.implement_pr_state ready_for_review "$1" 2>/dev/null)" || st=ready_for_review
  ips_publishes "$st"
}
IPS_E2E="$(mktemp)"
printf '%s' '{"devflow_implement":{"implement_pr_state":"draft"}}' > "$IPS_E2E"
assert_eq "implement_pr_state e2e: configured draft → leave draft"        "draft"   "$(ips_state_decision "$IPS_E2E")"
printf '%s' '{"devflow_implement":{}}' > "$IPS_E2E"
assert_eq "implement_pr_state e2e: absent key → publish"                  "publish" "$(ips_state_decision "$IPS_E2E")"
printf '%s' '{bad json' > "$IPS_E2E"
assert_eq "implement_pr_state e2e: malformed config (resolver hard-fail) → publish" "publish" "$(ips_state_decision "$IPS_E2E")"
rm -f "$IPS_E2E"

# Outcome guard mirroring the SKILL's FOUR-arm Phase 4.3 chain:
#   1. PR_STATE=draft                          → draft (no gh pr ready)
#   2. gh pr ready succeeds                     → published
#   3. gh pr ready fails BUT PR is non-draft    → published (idempotent re-run: gh pr ready
#                                                 returns non-zero on an already-ready PR)
#   4. else (still draft, or state unknown)     → publish_failed (fail-safe direction)
# The publish_failed capture (the workpad never falsely claims a PR was published on a
# `gh pr ready` failure) and the idempotent arm (a re-run of an already-published PR is
# NOT a failure) are the headline correctness properties of this change. Modelling all
# four arms here — plus the token pins below for the idempotent re-check command and
# breadcrumb — means a refactor that dropped the `else` arm OR the idempotent arm is
# caught. $1 = PR_STATE, $2 = simulated `gh pr ready` exit (0 ok / non-0), $3 = simulated
# `isDraft` re-check result ("true"/"false"/"" when the re-check itself errored).
ips_outcome() {
  [ "$1" = "draft" ] && { printf 'draft\n'; return; }
  if [ "${2:-0}" -eq 0 ]; then printf 'published\n'; return; fi
  [ "${3:-}" = "false" ] && { printf 'published\n'; return; }   # gh failed but PR already non-draft
  printf 'publish_failed\n'                                     # still draft, or state unconfirmed
}
assert_eq "implement_pr_state outcome: draft → draft (no gh pr ready)"                  "draft"          "$(ips_outcome draft 0)"
assert_eq "implement_pr_state outcome: publish + gh pr ready ok → published"            "published"      "$(ips_outcome ready_for_review 0)"
assert_eq "implement_pr_state outcome: gh fails + PR still draft → publish_failed"      "publish_failed" "$(ips_outcome ready_for_review 1 true)"
assert_eq "implement_pr_state outcome: gh fails + PR already non-draft → published (idempotent)" "published" "$(ips_outcome ready_for_review 1 false)"
assert_eq "implement_pr_state outcome: gh fails + state unconfirmed (re-check errored) → publish_failed (fail-safe)" "publish_failed" "$(ips_outcome ready_for_review 1 '')"

# Token pins for the publish_failed failure-capture branch, the idempotent re-run arm, and
# the outcome-specific finalize wording — the prior pass pinned only the draft note
# (`left as draft`), leaving the load-bearing "never falsely claim published" path and the
# idempotent re-check uncovered (a refactor dropping the isDraft arm would stay green).
assert_eq "implement_pr_state: SKILL captures the publish_failed outcome (gh pr ready failure not swallowed)" "yes" \
  "$(grep -qF 'PR_OUTCOME=publish_failed' "$IMPL_SKILL" && echo yes || echo no)"  # raw-guard-ok: non-unique: appears twice in implement SKILL (publish-failed paths)
assert_eq "implement_pr_state: SKILL leaves a gh-pr-ready failure breadcrumb" "yes" \
  "$(grep -qF 'gh pr ready FAILED' "$IMPL_SKILL" && echo yes || echo no)"  # raw-guard-ok: non-unique: appears twice in implement SKILL (publish-failed paths)
assert_pin_unique "implement_pr_state: SKILL keeps the idempotent already-non-draft re-check" 'gh pr view --json isDraft' "$IMPL_SKILL"
assert_eq "implement_pr_state: SKILL labels the idempotent re-run breadcrumb" "yes" \
  "$(grep -qF 'idempotent re-run' "$IMPL_SKILL" && echo yes || echo no)"  # raw-guard-ok: non-unique: 'idempotent re-run' appears twice in implement SKILL
# Couple the fail-safe construct: the re-check must redirect stderr (empty-on-error) AND
# compare against the literal `= "false"` — so an unconfirmed/errored re-check (empty
# substitution) is `!= "false"` and falls through to publish_failed (the conservative
# direction). Pinning the two together catches a silent fail-safe inversion (e.g. someone
# rewriting it as `!= "true"`, under which an empty result would wrongly read as published).
assert_pin_unique "implement_pr_state: SKILL idempotent re-check is fail-safe (2>/dev/null coupled to = \"false\")" '2>/dev/null)" = "false" ]' "$IMPL_SKILL"
assert_pin_unique "implement_pr_state: SKILL has a distinct published-outcome note" 'PR published (gh pr ready)' "$IMPL_SKILL"
assert_pin_unique "implement_pr_state: draft case posts no extra PR-thread comment (AC7)" 'no additional comment' "$IMPL_SKILL"

# Positional check: the clean-tree backstop must run ABOVE the publish gate (the diff's
# behavioral change is that it runs unconditionally in BOTH publish and draft cases), not
# merely be present somewhere. Assert line ordering, not bare presence.
# issue #218: grep the OWNING phase file, NOT the bundle. Both literals live in Phase 4.3
# (phases/phase-4-documentation.md). A POSITIONAL guard needs a single coordinate space with
# both endpoints unique; on the multi-file bundle, `head -1` of the generic `git status
# --porcelain` idiom could grab a future earlier-phase occurrence (lower bundle line number),
# making `-lt` pass vacuously. The owning file is the only space where both endpoints stay unique.
IPS_BACKSTOP_LN=$(grep -nF 'git status --porcelain' "$IMPL_PHASES_DIR/phase-4-documentation.md" | head -1 | cut -d: -f1)
IPS_GATE_LN=$(grep -nF '[ "$PR_STATE" = "draft" ]' "$IMPL_PHASES_DIR/phase-4-documentation.md" | head -1 | cut -d: -f1)
assert_eq "implement_pr_state: clean-tree backstop precedes the publish gate (runs in both cases)" "yes" \
  "$([ -n "$IPS_BACKSTOP_LN" ] && [ -n "$IPS_GATE_LN" ] && [ "$IPS_BACKSTOP_LN" -lt "$IPS_GATE_LN" ] && echo yes || echo no)"

# Cross-file Progress-label consistency. The Phase 4.3 finalize `--tick-progress` label
# in phases/phase-4-documentation.md MUST match the `## Progress` row label that scripts/workpad.py
# OWNS (its cmd_new_body template + _PROGRESS_PHASES tuple + _STATUS_TO_PROGRESS_PHASE
# 'complete' map) — workpad.py both renders the row and ticks it by substring, so if the
# two sides drift the finalize finds no matching unticked row and the Phase 4.3 update
# ABORTS. (This guards the exact desync a mid-review rename of the row to "PR finalized"
# introduced: SKILL renamed, workpad.py not.) Both sides are pinned to the same literal,
# so renaming one without the other goes red here.
WP_PY="$LIB/../scripts/workpad.py"
# NB: `--` ends grep's option parsing — the pattern begins with `--tick-progress`, which
# grep would otherwise treat as an (invalid) long option. pin_count now carries the same `--`
# guard (#374), so the flag shape is no longer the blocker; this stays a raw presence guard
# only because the literal is NON-UNIQUE across the bundle (it recurs in phase-4-documentation.md
# alongside the SKILL.md prose site), which assert_pin_unique (== 1) would reject.
assert_eq "implement finalize: SKILL ticks the workpad.py-owned 'PR marked ready' label" "yes" \
  "$(grep -qF -- '--tick-progress "PR marked ready"' "$IMPL_SKILL" && echo yes || echo no)"  # raw-guard-ok: non-unique: '--tick-progress "PR marked ready"' recurs across the bundle (SKILL.md prose + phase-4)
assert_eq "implement finalize: workpad.py owns the 'PR marked ready' label (template + _PROGRESS_PHASES agree)" "yes" \
  "$(grep -qF '**PR marked ready**' "$WP_PY" && grep -qF "'PR marked ready'" "$WP_PY" && echo yes || echo no)"

# ── issue #169: workpad.py tick failure-isolation + index ticking ─────────────
# Coupled contract across three files: scripts/workpad.py (the volatile-vs-structural
# behavior + the new --tick-ac-n/--tick-plan-n flags) ↔ the implement-skill bundle (the
# `workpad.py update` flag-table in the orchestrator SKILL.md AND the Phase 3.4 AC-tick
# call sites in phases/phase-3-review.md) ↔ this suite.
# The flag-table must document the index flags and the failure-isolation
# contract, and the Phase 3.4 gate must tick ACs by index rather than hand-picked
# substrings (the eight-fragile-substring foot-gun this issue removes). Editing one
# side without the others goes red here. (workpad.py's runtime behavior is pinned
# exhaustively in lib/test/test_python_scripts.py; these are the doc-mirror pins.)
assert_eq "#169: workpad.py defines the --tick-ac-n / --tick-plan-n index flags" "yes" \
  "$(grep -qF -- '--tick-ac-n' "$WP_PY" && grep -qF -- '--tick-plan-n' "$WP_PY" && echo yes || echo no)"
# SKILL-targeted pins route through assert_pin_unique (#157 AC2 raw-guard rule): the
# flag-table ROW literal is target-unique (count 1), so it pins exactly the doc row —
# stronger than a bare flag mention (which recurs across the table + call sites).
assert_pin_unique "#169: implement/SKILL.md flag-table documents --tick-ac-n (index AC tick)" \
  '| `--tick-ac-n N`' "$IMPL_SKILL"
assert_pin_unique "#169: implement/SKILL.md flag-table documents --tick-plan-n (index Plan tick)" \
  '| `--tick-plan-n N`' "$IMPL_SKILL"
# The named contract heading is target-unique (a bare 'volatile' grep would stay green
# if the contract paragraph were deleted but the word survived elsewhere).
assert_pin_unique "#169: implement/SKILL.md carries the named volatile-vs-structural failure-isolation contract" \
  'Failure-isolation contract (volatile vs. structural)' "$IMPL_SKILL"
# ABSENCE pin (the hand-picked substring example must be GONE) — assert_pin_unique
# (count==1) cannot express absence, so it carries an explicit #157 allowlist marker.
assert_eq "#169: Phase 3.4 AC-tick uses the index form (no hand-picked '{substring of AC text}')" "yes" \
  "$(grep -qF -- '--tick-ac "{substring of AC text}"' "$IMPL_SKILL" && echo no || echo yes)"  # raw-guard-ok: absence pin — the superseded substring example must be GONE
# Finding 1 (review): the gate must CONSUME the new non-zero-exit contract — the SKILL
# tells callers a tick's non-zero exit means it did not land (never advance on the
# stdout body alone). Target-unique phrase → assert_pin_unique.
assert_pin_unique "#169: implement/SKILL.md tells callers to check the tick exit code, not the stdout body alone" \
  'never advance on the stdout body alone' "$IMPL_SKILL"
# Finding 4 (review): ABSENCE pin — the stale '--tick-ac later' note must be gone
# (replaced by '--tick-ac-n'); allowlist marker per #157 (absence is not expressible
# via assert_pin_unique).
assert_eq "#169: implement/SKILL.md 2.2.6 note references the index gate-tick flag (no stale '--tick-ac later')" "yes" \
  "$(grep -qF 'will tick via `--tick-ac` later' "$IMPL_SKILL" && echo no || echo yes)"  # raw-guard-ok: absence pin — the superseded '--tick-ac later' note must be GONE
# Shadow Finding 2 (review): the SKILL tells callers a volatile miss already PATCHed the
# status/notes, so on a non-zero exit they re-tick ONLY the row(s) and do not re-send the
# whole call (which would double-write append-only notes). Coupled with workpad.py's
# breadcrumb wording, which test_python_scripts.py shadow-F2 pins. Target-unique phrase.
assert_pin_unique "#169: implement/SKILL.md warns re-tick-only (don't re-send the whole call on a volatile miss)" \
  'do not blindly re-send the whole call' "$IMPL_SKILL"
# Shadow Finding 1 (review): workpad.py reports volatile misses on the gh-PATCH-failure
# path too (not just the structural-abort and clean-PATCH paths), via the single
# _report_failed_ticks chokepoint — so a miss collected before a 5xx/auth PATCH failure
# is never silently dropped. test_python_scripts.py shadow-F1 pins the behavior.
assert_eq "#169: workpad.py routes volatile misses through _report_failed_ticks (PATCH-failure echo)" "yes" \
  "$(grep -qF 'def _report_failed_ticks' "$WP_PY" && grep -qF 'NO workpad change was persisted' "$WP_PY" && echo yes || echo no)"

# ── issue #258: terminal --status Complete self-record gate ───────────────────
# scripts/workpad.py, on a `--status Complete` write, must reconcile the workpad's
# self-record against reality: hard-fail (structural: non-zero exit, NO PATCH,
# Status not flipped) when any NON-post-merge ## Acceptance Criteria row is still
# `- [ ]`, and emit a NON-blocking stderr warning naming any unticked ## Plan row
# while still finalizing. The gate fires ONLY for --status Complete; it never
# modifies a `- [ ]` row. Exercised here as a real CLI subprocess against a gh
# stub (the five AC-7 scenarios), and pinned exhaustively at the _apply_mutations
# level in lib/test/test_python_scripts.py. Two scenarios go RED against the
# pre-gate workpad.py — (a): old code PATCHed Complete over an unticked AC; (c):
# old code emitted no Plan warning. (b)/(d)/(e) are controls that pass identically
# on old and new code — they guard against the gate OVER-firing (post-merge-only,
# all-ticked, and --status Blocked must NOT be blocked or warned).
S258="$(mktemp -d)"
cat > "$S258/gh" <<'STUB'
#!/usr/bin/env bash
# Minimal gh stub for workpad.py update: repo view, comments list (marker match),
# body fetch, and PATCH (records that a PATCH happened + echoes the patched body).
j="$*"
if [[ "$j" == *"repo view"* ]]; then echo "owner/repo"; exit 0; fi
if [[ "$j" == *"-X PATCH"* ]]; then
  echo p >> "$WP_PATCHLOG"
  for a in "$@"; do case "$a" in body=@*) cat "${a#body=@}";; esac; done
  exit 0
fi
if [[ "$j" == *"issues/comments/7"* ]]; then cat "$WP_BODY"; exit 0; fi
if [[ "$j" == *"issues/999/comments"* ]]; then echo '[{"id":7,"body":"<!-- devflow:workpad -->"}]'; exit 0; fi
echo '[]'
STUB
chmod +x "$S258/gh"

# Fixture bodies. Base = every Plan/AC row ticked (the clean-run shape).
cat > "$S258/all-ticked.md" <<'WPMD'
<!-- devflow:workpad -->
# DevFlow Workpad — Issue #999

**Status:** 🚀 Documenting
**Last updated:** 2026-05-15T00:00:00Z

## Progress
- [x] **Setup**

## Plan
- [x] Plan step one
- [x] Plan step two

## Acceptance Criteria
- [x] AC one
- [x] AC two
WPMD
# (a) a non-post-merge AC row still unticked.
sed 's/- \[x\] AC two/- [ ] AC two/' "$S258/all-ticked.md" > "$S258/ac-unticked.md"
# (b) the ONLY outstanding AC row carries the (post-merge) marker.
sed 's/- \[x\] AC two/- [ ] AC two (post-merge)/' "$S258/all-ticked.md" > "$S258/ac-postmerge.md"
# (c) a ## Plan row unticked, every AC ticked.
sed 's/- \[x\] Plan step two/- [ ] Plan step two/' "$S258/all-ticked.md" > "$S258/plan-unticked.md"

# run258 <body-file> <args...> → prints the exit code; leaves out/err/patchlog on disk.
run258() {
  local body="$1"; shift
  : > "$S258/patchlog"
  WP_BODY="$body" WP_PATCHLOG="$S258/patchlog" DEVFLOW_GH="$S258/gh" \
    python3 "$WP_PY" update 999 "$@" >"$S258/out" 2>"$S258/err"
  echo $?
}

# (a) --status Complete aborts non-zero with NO PATCH when a non-post-merge AC is [ ].
_c="$(run258 "$S258/ac-unticked.md" --status Complete)"
assert_eq "#258(a): --status Complete aborts non-zero on an unticked non-post-merge AC" "no" \
  "$([ "$_c" = "0" ] && echo yes || echo no)"
assert_eq "#258(a): the abort made NO PATCH (self-record not flipped to Complete)" "yes" \
  "$([ -s "$S258/patchlog" ] && echo no || echo yes)"
assert_eq "#258(a): the abort names the offending AC row on stderr" "yes" \
  "$(grep -q 'AC two' "$S258/err" && echo yes || echo no)"

# (b) only outstanding AC is (post-merge) → finalizes normally (PATCH, Status flipped).
_c="$(run258 "$S258/ac-postmerge.md" --status Complete)"
assert_eq "#258(b): a post-merge-only outstanding AC finalizes (exit 0)" "0" "$_c"
assert_eq "#258(b): the post-merge-only finalize PATCHed the Status to Complete" "yes" \
  "$(grep -q '🎉 Complete' "$S258/out" && echo yes || echo no)"

# (c) a ## Plan row unticked → succeeds-with-warning (non-blocking), Status flips.
_c="$(run258 "$S258/plan-unticked.md" --status Complete)"
assert_eq "#258(c): an unticked Plan row does NOT block finalize (exit 0)" "0" "$_c"
assert_eq "#258(c): finalize emits a non-blocking Plan warning naming the unticked row" "yes" \
  "$(grep -qi 'plan' "$S258/err" && grep -q 'Plan step two' "$S258/err" && echo yes || echo no)"
assert_eq "#258(c): the Plan-warning finalize still flipped Status to Complete" "yes" \
  "$(grep -q '🎉 Complete' "$S258/out" && echo yes || echo no)"

# (d) all rows ticked → succeeds silently (no AC abort, no Plan warning).
_c="$(run258 "$S258/all-ticked.md" --status Complete)"
assert_eq "#258(d): a fully-ticked run finalizes (exit 0)" "0" "$_c"
assert_eq "#258(d): a fully-ticked finalize emits NO Plan/AC gate warning" "yes" \
  "$(grep -qiE 'unticked|refusing to finalize' "$S258/err" && echo no || echo yes)"

# (e) --status Blocked with an unticked AC is NEVER gated (behaves as today).
_c="$(run258 "$S258/ac-unticked.md" --status Blocked)"
assert_eq "#258(e): --status Blocked with an unticked AC is not gated (exit 0)" "0" "$_c"
assert_eq "#258(e): --status Blocked with an unticked AC still PATCHed (Status → Blocked)" "yes" \
  "$([ -s "$S258/patchlog" ] && grep -q '👎 Blocked' "$S258/out" && echo yes || echo no)"

# Source pin: the terminal gate + its post-merge exclusion live in workpad.py.
assert_eq "#258: workpad.py carries the terminal --status Complete self-record gate" "yes" \
  "$(grep -q '_terminal_complete_gate' "$WP_PY" && grep -q "(post-merge)" "$WP_PY" && echo yes || echo no)"
rm -rf "$S258"

# ── issue #356: 💥 Failed terminal workpad status + dead-run flips ─────────────
# A cloud run that dies (job failure/cancel/exhausted auto-resume) must stop its
# Status-bearing comment lying. Two flips, one vocabulary each:
#   - implement workpad → new canonical terminal word `Failed`, glyph 💥
#   - review progress comment → the skill's existing `❌ Review failed` state
# Coupled invariant: 💥 is mirrored across workpad.py's _STATUS_GLYPHS,
# fetch-pr-context.sh's glyph strip, and the docs; the `❌ Review failed` literal
# and the run-keyed marker are a coupled contract with skills/review/SKILL.md.
S356="$(mktemp -d)"
cat > "$S356/gh" <<'STUB'
#!/usr/bin/env bash
# Minimal gh stub for workpad.py (status/update) and flip-review-progress-failed.sh
# (id/body/patch). Comments-list returns the full WP_BODY so `status` (which reads
# the body straight from the list) and `id`/`update` (which then fetch it) both work.
j="$*"
if [[ "$j" == *"repo view"* ]]; then echo "owner/repo"; exit 0; fi
if [[ "$j" == *"-X PATCH"* ]]; then
  if [ -n "${WP_PATCH_FAIL:-}" ]; then echo "patch boom" >&2; exit 1; fi
  echo p >> "$WP_PATCHLOG"
  for a in "$@"; do case "$a" in body=@*) cat "${a#body=@}" | tee "${WP_PATCHBODY:-/dev/null}";; esac; done
  exit 0
fi
if [[ "$j" == *"issues/comments/7"* ]]; then
  # WP_BODY_FAIL: the single-comment read fails (403/5xx) -> workpad.py body rc 1.
  if [ -n "${WP_BODY_FAIL:-}" ]; then echo "body boom" >&2; exit 1; fi
  cat "$WP_BODY"; exit 0
fi
if [[ "$j" == *"/comments"* ]]; then
  # WP_ID_FAIL: the comment-LIST read fails (rate limit/403/5xx) -> workpad.py id
  # rc 1. Distinct from WP_ABSENT (a clean scan finding nothing -> rc 2): the flip
  # helper must diagnose these differently, never calling a failed read "absent".
  if [ -n "${WP_ID_FAIL:-}" ]; then echo "list boom" >&2; exit 1; fi
  if [ -n "${WP_ABSENT:-}" ]; then echo '[]'; exit 0; fi
  printf '[{"id":7,"body":%s}]' "$(jq -Rs . < "$WP_BODY")"; exit 0
fi
echo '[]'
STUB
chmod +x "$S356/gh"

# Fixture: an interim (🚀 Implementing) workpad with Setup ticked, Implement not,
# and an unticked non-post-merge AC (to exercise the Complete-only-gate carve-out).
cat > "$S356/interim.md" <<'WPMD'
<!-- devflow:workpad -->
# DevFlow Workpad — Issue #888

**Status:** 🚀 Implementing
**Last updated:** 2026-07-09T00:00:00Z

## Progress
- [x] **Setup** — branch & workpad
- [ ] **Implement**

## Plan
- [ ] do the thing

## Acceptance Criteria
- [ ] AC one
WPMD
# A body already carrying the terminal 💥 Failed status (for status + idempotency).
sed 's/🚀 Implementing/💥 Failed/' "$S356/interim.md" > "$S356/failed.md"

run356() {  # <body-file> <args...> → prints exit code; leaves out/err/patchlog on disk.
  local body="$1"; shift
  : > "$S356/patchlog"
  WP_BODY="$body" WP_PATCHLOG="$S356/patchlog" DEVFLOW_GH="$S356/gh" \
    python3 "$WP_PY" update 888 "$@" >"$S356/out" 2>"$S356/err"
  echo $?
}

# AC: `workpad.py status` prints `terminal 💥 Failed` exit 0 for a 💥 Failed body.
_so="$(WP_BODY="$S356/failed.md" DEVFLOW_GH="$S356/gh" python3 "$WP_PY" status 888 2>/dev/null)"; _src=$?
assert_eq "#356: workpad.py status prints 'terminal 💥 Failed' for a 💥 Failed body" "terminal 💥 Failed" "$_so"
assert_eq "#356: workpad.py status exits 0 for a 💥 Failed body" "0" "$_src"

# AC: update --status Failed writes 💥 Failed and does NOT trip the Complete-only gate.
_c="$(run356 "$S356/interim.md" --status Failed)"
assert_eq "#356: update --status Failed succeeds (exit 0) even with an unticked non-post-merge AC" "0" "$_c"
assert_eq "#356: update --status Failed writes '**Status:** 💥 Failed'" "yes" \
  "$(grep -q '^\*\*Status:\*\* 💥 Failed$' "$S356/out" && echo yes || echo no)"
assert_eq "#356: update --status Failed PATCHed (Complete-only gate not tripped)" "yes" \
  "$([ -s "$S356/patchlog" ] && echo yes || echo no)"
# The three assertions above prove Failed BYPASSES the gate — but they would all stay
# GREEN if the gate were deleted outright. Pin that the gate is Complete-ONLY by also
# asserting the CONTRAST on the identical fixture: --status Complete over the same
# unticked non-post-merge AC must abort (non-zero, no PATCH). Without this row the
# carve-out pin asserts nothing about the gate's existence.
: > "$S356/patchlog"
_c="$(run356 "$S356/interim.md" --status Complete)"
assert_eq "#356: --status Complete on the SAME unticked-AC fixture aborts (gate is Complete-only)" "yes" \
  "$([ "$_c" = "0" ] && echo no || echo yes)"
assert_eq "#356: --status Complete on an unticked AC makes NO PATCH (structural abort)" "yes" \
  "$([ -s "$S356/patchlog" ] && echo no || echo yes)"

# AC: re-applying --status Failed to a 💥 Failed body is idempotent (single glyph).
_c="$(run356 "$S356/failed.md" --status Failed)"
assert_eq "#356: re-applying --status Failed stays exit 0" "0" "$_c"
assert_eq "#356: re-applying --status Failed yields one 💥, not '💥 💥'" "yes" \
  "$(grep -q '^\*\*Status:\*\* 💥 Failed$' "$S356/out" && ! grep -q '💥 💥' "$S356/out" && echo yes || echo no)"

# AC: Failed is absent from _STATUS_TO_PROGRESS_PHASE, so a --note nests under the
# most-recent-ticked phase (Setup here) — the same fallback Blocked uses.
_c="$(run356 "$S356/interim.md" --status Failed --note "died here")"
assert_eq "#356: --status Failed --note nests under the most-recent-ticked phase (Setup)" "yes" \
  "$(python3 -c "
t=open('$S356/out').read().splitlines()
si=[i for i,l in enumerate(t) if 'Setup' in l and l.startswith('- [')]
ii=[i for i,l in enumerate(t) if 'Implement' in l and l.startswith('- [')]
ni=[i for i,l in enumerate(t) if 'died here' in l]
print('yes' if si and ii and ni and si[0]<ni[0]<ii[0] else 'no')
")"

# Source pins: the 💥 vocabulary lives in workpad.py (single source of truth).
assert_eq "#356: workpad.py _STATUS_GLYPHS includes 💥 (extended tuple)" "yes" \
  "$(grep -q "💥')" "$WP_PY" && echo yes || echo no)"
assert_eq "#356: workpad.py maps 'failed' → 💥 (write path) and leaves it out of _STATUS_TO_PROGRESS_PHASE" "yes" \
  "$(grep -q "return '💥'" "$WP_PY" && ! grep -q "'failed':" "$WP_PY" && echo yes || echo no)"

# ── flip-review-progress-failed.sh unit tests ─────────────────────────────────
FLIP_SH="$LIB/../scripts/flip-review-progress-failed.sh"
RMARK="<!-- devflow:review-progress run=RUNTEST-1 -->"
# Interim review-progress comment (🚀 Reviewing) — the flip candidate.
cat > "$S356/rev-interim.md" <<RMD
$RMARK
# Devflow Review — PR #55

**Status:** 🚀 Reviewing

## Blueprint
- [ ] step one
RMD
# Terminal review-progress comment (already ❌ Review failed) — must NOT be touched.
sed 's/🚀 Reviewing/❌ Review failed/' "$S356/rev-interim.md" > "$S356/rev-terminal.md"

# (flipped) 🚀 Reviewing → ❌ Review failed, cause line appended, PATCH made, exit 0.
: > "$S356/patchlog"; : > "$S356/patchbody"
WP_BODY="$S356/rev-interim.md" WP_PATCHLOG="$S356/patchlog" WP_PATCHBODY="$S356/patchbody" DEVFLOW_GH="$S356/gh" \
  bash "$FLIP_SH" 55 "$RMARK" "job died" >/dev/null 2>"$S356/ferr"; _fc=$?
assert_eq "#356 flip: exits 0 on a successful flip" "0" "$_fc"
# The stub records the patched body it received to WP_PATCHBODY.
assert_eq "#356 flip: rewrote the Status line to '❌ Review failed'" "yes" \
  "$(grep -q '^\*\*Status:\*\* ❌ Review failed$' "$S356/patchbody" && echo yes || echo no)"
assert_eq "#356 flip: the interim 🚀 Reviewing status is gone after the flip" "yes" \
  "$(grep -q '🚀 Reviewing' "$S356/patchbody" && echo no || echo yes)"
assert_eq "#356 flip: a one-line cause is appended" "yes" \
  "$(grep -q 'job died' "$S356/patchbody" && echo yes || echo no)"
assert_eq "#356 flip: breadcrumb names the 'flipped' arm" "yes" \
  "$(grep -qi 'flipped' "$S356/ferr" && echo yes || echo no)"
assert_eq "#356 flip: a PATCH was actually made" "yes" \
  "$([ -s "$S356/patchlog" ] && echo yes || echo no)"

# (already-terminal) a ❌ Review failed comment is left untouched, exit 0, no PATCH.
: > "$S356/patchlog"
WP_BODY="$S356/rev-terminal.md" WP_PATCHLOG="$S356/patchlog" DEVFLOW_GH="$S356/gh" \
  bash "$FLIP_SH" 55 "$RMARK" "job died" >/dev/null 2>"$S356/ferr"; _fc=$?
assert_eq "#356 flip: exits 0 on an already-terminal comment" "0" "$_fc"
assert_eq "#356 flip: makes NO PATCH on an already-terminal comment" "yes" \
  "$([ -s "$S356/patchlog" ] && echo no || echo yes)"
assert_eq "#356 flip: breadcrumb names the already-terminal arm" "yes" \
  "$(grep -qi 'already terminal' "$S356/ferr" && echo yes || echo no)"

# (comment absent) no matching run-keyed marker → comment-absent no-op, exit 0.
: > "$S356/patchlog"
WP_BODY="$S356/rev-interim.md" WP_PATCHLOG="$S356/patchlog" WP_ABSENT=1 DEVFLOW_GH="$S356/gh" \
  bash "$FLIP_SH" 55 "$RMARK" "job died" >/dev/null 2>"$S356/ferr"; _fc=$?
assert_eq "#356 flip: exits 0 when no progress comment exists" "0" "$_fc"
assert_eq "#356 flip: comment-absent arm makes NO PATCH" "yes" \
  "$([ -s "$S356/patchlog" ] && echo no || echo yes)"
assert_eq "#356 flip: breadcrumb names the comment-absent arm" "yes" \
  "$(grep -qi 'comment-absent' "$S356/ferr" && echo yes || echo no)"

# (patch failure) the PATCH itself fails → exit 0, failure breadcrumb.
: > "$S356/patchlog"
WP_BODY="$S356/rev-interim.md" WP_PATCHLOG="$S356/patchlog" WP_PATCH_FAIL=1 DEVFLOW_GH="$S356/gh" \
  bash "$FLIP_SH" 55 "$RMARK" "job died" >/dev/null 2>"$S356/ferr"; _fc=$?
assert_eq "#356 flip: exits 0 even when the PATCH fails" "0" "$_fc"
assert_eq "#356 flip: patch-failure breadcrumb names the failure arm" "yes" \
  "$(grep -qi 'patch-failure' "$S356/ferr" && echo yes || echo no)"

# (id read failure) `workpad.py id` rc 1 (a gh-api/parse failure) is a READ failure,
# NOT "comment-absent" (rc 2). Misreporting a failed lookup as an absent comment
# sends an operator hunting for a comment that in fact exists, so the two arms
# carry distinct breadcrumbs. Both are still best-effort no-ops (exit 0, no PATCH).
: > "$S356/patchlog"
WP_BODY="$S356/rev-interim.md" WP_PATCHLOG="$S356/patchlog" WP_ID_FAIL=1 DEVFLOW_GH="$S356/gh" \
  bash "$FLIP_SH" 55 "$RMARK" "job died" >/dev/null 2>"$S356/ferr"; _fc=$?
assert_eq "#356 flip: exits 0 when the comment lookup itself fails" "0" "$_fc"
assert_eq "#356 flip: id-read-failure arm makes NO PATCH" "yes" \
  "$([ -s "$S356/patchlog" ] && echo no || echo yes)"
assert_eq "#356 flip: a failed lookup is diagnosed as a read failure, not 'comment-absent'" "yes" \
  "$(grep -qi 'read-failure' "$S356/ferr" && ! grep -qi 'comment-absent' "$S356/ferr" && echo yes || echo no)"
assert_eq "#356 flip: id-read-failure breadcrumb states absence was not established" "yes" \
  "$(grep -q 'absence was NOT established' "$S356/ferr" && echo yes || echo no)"
# Assert the CAUSE CONTENT, not just the arm name: a breadcrumb that names the arm but
# carries an empty `Cause:` delivers none of the diagnostic value it exists for. (The
# stub writes `list boom` to workpad.py's stderr; a short cause must survive the clamp
# — bash's `${c: -N}` yields EMPTY when the string is shorter than N.)
assert_eq "#356 flip: id-read-failure breadcrumb carries the underlying gh cause" "yes" \
  "$(grep -qi 'list boom' "$S356/ferr" && echo yes || echo no)"

# (body read failure) the comment id resolves but the body read fails → read-failure
# no-op, exit 0, no PATCH.
: > "$S356/patchlog"
WP_BODY="$S356/rev-interim.md" WP_PATCHLOG="$S356/patchlog" WP_BODY_FAIL=1 DEVFLOW_GH="$S356/gh" \
  bash "$FLIP_SH" 55 "$RMARK" "job died" >/dev/null 2>"$S356/ferr"; _fc=$?
assert_eq "#356 flip: exits 0 when the body read fails" "0" "$_fc"
assert_eq "#356 flip: body-read-failure arm makes NO PATCH" "yes" \
  "$([ -s "$S356/patchlog" ] && echo no || echo yes)"
assert_eq "#356 flip: body-read-failure breadcrumb names the read-failure arm" "yes" \
  "$(grep -qi 'could not read body' "$S356/ferr" && echo yes || echo no)"
assert_eq "#356 flip: body-read-failure breadcrumb carries the underlying gh cause" "yes" \
  "$(grep -qi 'body boom' "$S356/ferr" && echo yes || echo no)"

# (missing args) no pr number / no marker → usage no-op, exit 0, no PATCH.
: > "$S356/patchlog"
WP_PATCHLOG="$S356/patchlog" DEVFLOW_GH="$S356/gh" \
  bash "$FLIP_SH" "" "$RMARK" "job died" >/dev/null 2>"$S356/ferr"; _fc=$?
assert_eq "#356 flip: exits 0 with a missing pr number" "0" "$_fc"
assert_eq "#356 flip: missing-args arm makes NO PATCH" "yes" \
  "$([ -s "$S356/patchlog" ] && echo no || echo yes)"
# An empty PR and an empty MARKER are DIFFERENT no-op modes and must not share one
# breadcrumb: the empty-PR path is reachable in production (finalize_check passes a
# possibly-empty pr_number output), the empty-marker path is a caller bug.
assert_eq "#356 flip: empty-pr breadcrumb names the pr number specifically" "yes" \
  "$(grep -qi 'empty pr number' "$S356/ferr" && ! grep -qi 'empty marker' "$S356/ferr" && echo yes || echo no)"
: > "$S356/patchlog"
WP_PATCHLOG="$S356/patchlog" DEVFLOW_GH="$S356/gh" \
  bash "$FLIP_SH" 55 "" "job died" >/dev/null 2>"$S356/ferr"; _fc=$?
assert_eq "#356 flip: exits 0 with a missing marker" "0" "$_fc"
assert_eq "#356 flip: missing-marker arm makes NO PATCH" "yes" \
  "$([ -s "$S356/patchlog" ] && echo no || echo yes)"
assert_eq "#356 flip: empty-marker breadcrumb names the marker specifically" "yes" \
  "$(grep -qi 'empty marker' "$S356/ferr" && ! grep -qi 'empty pr number' "$S356/ferr" && echo yes || echo no)"

# (NOSTATUS) the comment exists and the marker matches, but it carries no `**Status:**`
# line -> no flip, exit 0, no PATCH. This arm is reachable if the review skill's seed
# format ever drifts, so it must fail CLOSED (never PATCH a body it cannot parse).
cat > "$S356/rev-nostatus.md" <<RMD
$RMARK
# Devflow Review — PR #55

Status is missing entirely.
RMD
: > "$S356/patchlog"
WP_BODY="$S356/rev-nostatus.md" WP_PATCHLOG="$S356/patchlog" DEVFLOW_GH="$S356/gh" \
  bash "$FLIP_SH" 55 "$RMARK" "job died" >/dev/null 2>"$S356/ferr"; _fc=$?
assert_eq "#356 flip: exits 0 on a comment with no Status line" "0" "$_fc"
assert_eq "#356 flip: no-Status arm makes NO PATCH (fails closed)" "yes" \
  "$([ -s "$S356/patchlog" ] && echo no || echo yes)"
assert_eq "#356 flip: no-Status breadcrumb names its own arm" "yes" \
  "$(grep -qi 'has no Status line' "$S356/ferr" && echo yes || echo no)"

# Coupled contract: the helper's interim test keys on a `**Status:** 🚀 Reviewing`
# line that skills/review/SKILL.md seeds. Pin the SEED SHAPE, not just the terminal
# literal — a seed drift to e.g. `**Status**:` would silently route every flip to the
# NOSTATUS no-op arm above while every other pin stayed green.
assert_pin_unique "#356 pin: skills/review/SKILL.md seeds the '**Status:** 🚀 Reviewing' line the helper matches" \
  '**Status:** 🚀 Reviewing' "$LIB/../skills/review/SKILL.md"

# (non-numeric pr) `workpad.py id` declares its issue arg type=int, so ARGPARSE also
# exits 2 on a usage error — the same rc cmd_id uses for "scanned cleanly, no match".
# The helper must refuse a non-numeric PR before the id call, so the rc-2 arm stays
# unambiguous and a malformed invocation is never reported as "comment-absent".
: > "$S356/patchlog"
WP_BODY="$S356/rev-interim.md" WP_PATCHLOG="$S356/patchlog" DEVFLOW_GH="$S356/gh" \
  bash "$FLIP_SH" "not-a-number" "$RMARK" "job died" >/dev/null 2>"$S356/ferr"; _fc=$?
assert_eq "#356 flip: exits 0 on a non-numeric pr number" "0" "$_fc"
assert_eq "#356 flip: non-numeric pr makes NO PATCH" "yes" \
  "$([ -s "$S356/patchlog" ] && echo no || echo yes)"
assert_eq "#356 flip: a non-numeric pr is NOT reported as 'comment-absent'" "yes" \
  "$(grep -qi 'not numeric' "$S356/ferr" && ! grep -qi 'comment-absent' "$S356/ferr" && echo yes || echo no)"

# (missing workpad.py sibling) `python3` ALSO exits 2 when it cannot open the script —
# `can't open file … [Errno 2]` on a partial vendor copy, `[Errno 13]` on a mode-000 file
# — the same rc `cmd_id` uses for "scanned cleanly, no match". Without a screen, that
# interpreter-level rc 2 lands in the comment-absent arm and tells an operator the comment
# does not exist when the read never happened. Copy the helper WITHOUT its workpad.py
# sibling to drive the real deployment shape, and assert it takes a read-failure arm.
mkdir -p "$S356/lonely"
cp "$FLIP_SH" "$S356/lonely/flip-review-progress-failed.sh"
: > "$S356/patchlog"
WP_BODY="$S356/rev-interim.md" WP_PATCHLOG="$S356/patchlog" DEVFLOW_GH="$S356/gh" \
  bash "$S356/lonely/flip-review-progress-failed.sh" 55 "$RMARK" "job died" >/dev/null 2>"$S356/ferr"; _fc=$?
assert_eq "#356 flip: exits 0 when its workpad.py sibling is missing" "0" "$_fc"
assert_eq "#356 flip: a missing workpad.py sibling makes NO PATCH" "yes" \
  "$([ -s "$S356/patchlog" ] && echo no || echo yes)"
assert_eq "#356 flip: a missing workpad.py sibling is NOT reported as 'comment-absent'" "yes" \
  "$(! grep -qi 'comment-absent' "$S356/ferr" && echo yes || echo no)"
assert_eq "#356 flip: a missing workpad.py sibling states absence was NOT established" "yes" \
  "$(grep -q 'absence was NOT established' "$S356/ferr" && echo yes || echo no)"
# The helper screens this class TWICE — a readable-sibling precheck and an rc-2 + non-empty
# stderr discriminator — and either alone yields a read-failure arm. So asserting only the
# OUTCOME leaves both guards individually deletable with the suite still GREEN. Pin the
# PRECHECK specifically, by the breadcrumb only it emits: the discriminator's message names
# python3's exit, never "a partial vendor copy". Deleting the precheck alone now goes RED.
# (The precheck is the robust half: the discriminator no-ops when $WP_ERR could not be
# allocated, and relies on --marker always being explicit.)
assert_eq "#356 flip: the readable-sibling PRECHECK fired (not merely the rc-2 stderr discriminator)" "yes" \
  "$(grep -q 'missing or unreadable — a partial vendor copy?' "$S356/ferr" && echo yes || echo no)"
# An unreadable (mode-000) sibling is the same class and must take the same arm, not the
# comment-absent one. Skip under a uid that ignores the mode bit (e.g. root in a container).
cp "$WP_PY" "$S356/lonely/workpad.py"
chmod 000 "$S356/lonely/workpad.py"
if [ ! -r "$S356/lonely/workpad.py" ]; then
  : > "$S356/patchlog"
  WP_BODY="$S356/rev-interim.md" WP_PATCHLOG="$S356/patchlog" DEVFLOW_GH="$S356/gh" \
    bash "$S356/lonely/flip-review-progress-failed.sh" 55 "$RMARK" "job died" >/dev/null 2>"$S356/ferr"; _fc=$?
  assert_eq "#356 flip: exits 0 when its workpad.py sibling is unreadable" "0" "$_fc"
  assert_eq "#356 flip: an unreadable workpad.py sibling is NOT reported as 'comment-absent'" "yes" \
    "$(! grep -qi 'comment-absent' "$S356/ferr" && echo yes || echo no)"
else
  # Never skip SILENTLY: under a uid that ignores the mode bit (root in a container) the
  # two assertions above cannot run, and a quietly-lower assertion count is precisely the
  # unaudited coverage loss the rest of this block exists to catch.
  echo "  SKIP  #356 flip: unreadable-sibling arm (this uid ignores the mode bit; chmod 000 stayed readable)"
fi
chmod 644 "$S356/lonely/workpad.py" 2>/dev/null || true

# Helper contract pins: SPDX header + always-exit-0 + routes via workpad.py (no bare gh).
# ── #356: the two skill-side enumerations of the status vocabulary this issue extends ──
# `Failed`/💥 is a new member of workpad.py's CLOSED status model, so every skill body that
# enumerates that model must name it. These two sites are operative (an agent reads them at
# runtime), unpinned before this change, and were left stale by the first pass — pin them so
# a future glyph addition cannot silently desync them again.
assert_pin_unique "#356: implement SKILL's --status row names the full canonical glyph set (incl. 💥)" \
  'the helper prepends the canonical glyph (🚀/🎉/👎/💥)' "$LIB/../skills/implement/SKILL.md"
assert_pin_red_on_removal "#356: implement SKILL canonical-glyph-set clause flips RED on removal" \
  'the helper prepends the canonical glyph (🚀/🎉/👎/💥)' "$LIB/../skills/implement/SKILL.md"
assert_pin_unique "#356: retrospective SKILL enumerates Failed among the terminal workpad_final_status values" \
  '`Complete` / `Blocked` / `Failed`' "$LIB/../skills/retrospective/SKILL.md"
assert_pin_red_on_removal "#356: retrospective SKILL terminal-status enumeration flips RED on removal" \
  '`Complete` / `Blocked` / `Failed`' "$LIB/../skills/retrospective/SKILL.md"

assert_eq "#356 flip: helper carries the SPDX header" "yes" \
  "$(grep -q 'SPDX-License-Identifier: MIT' "$FLIP_SH" && echo yes || echo no)"
assert_eq "#356 flip: helper routes GitHub access through workpad.py (no bare gh invocation)" "yes" \
  "$(grep -q 'workpad.py' "$FLIP_SH" && ! grep -qE '(^|[^A-Za-z_.])gh (api|issue|pr|label|repo)' "$FLIP_SH" && echo yes || echo no)"
# Coupled contract with skills/review/SKILL.md (the agent-side fatal-abort rule):
# the `❌ Review failed` literal must match. Pin the SKILL side uniquely (a rename
# there goes RED); assert the helper carries the matching literal via grep_present.
assert_pin_unique "#356 flip: skills/review/SKILL.md carries the '❌ Review failed' literal the helper mirrors" \
  '❌ Review failed' "$LIB/../skills/review/SKILL.md"
assert_eq "#356 flip: helper carries the matching '❌ Review failed' literal" "yes" \
  "$(grep -qF '❌ Review failed' "$FLIP_SH" && echo yes || echo no)"

# ── Run-keyed MARKER shape: the OTHER half of the coupled contract ─────────────
# The helper finds the comment with `workpad.py id --marker "$FLIP_MARKER"`. If the review
# skill's SEED marker and the workflows' FLIP_MARKER ever drift apart, `id` returns rc 2,
# the helper takes its comment-absent no-op arm, exits 0 — and BOTH dead-run flips silently
# never fire. That is a fail-open in exactly the scenario the flip exists to cover, and
# nothing else in the suite goes RED for it. `flip-review-progress-failed.sh`'s header and
# docs/DEVFLOW_SYSTEM_OVERVIEW.md both assert this marker shape is "pinned in
# lib/test/run.sh" — these are the pins that make that claim true.
#
# The producer and consumer are not byte-identical (the skill defaults the env for a local
# run; the workflows rely on Actions always setting it), so pin the invariant *sub-shape*
# each carries, plus the identity of the two workflow literals.
#
# Declared here rather than reused from the workflow-wiring block below: that block defines
# $REVIEW_YML/$DEVFLOW_YML further down, and this block must not depend on statement order.
M356_REVIEW_YML="$LIB/../.github/workflows/devflow-review.yml"
M356_DEVFLOW_YML="$LIB/../.github/workflows/devflow.yml"
assert_pin_unique "#356 marker: skills/review/SKILL.md seeds the run-keyed review-progress marker" \
  'MARKER=$(printf '"'"'%s'"'"' "<!-- devflow:review-progress run=${GITHUB_RUN_ID:-local-$(date -u +%Y%m%dT%H%M%SZ)}-${GITHUB_RUN_ATTEMPT:-1} -->")' \
  "$LIB/../skills/review/SKILL.md"
assert_pin_red_on_removal "#356 marker: the SKILL.md seed-marker line flips RED on removal" \
  'MARKER=$(printf '"'"'%s'"'"' "<!-- devflow:review-progress run=${GITHUB_RUN_ID:-local-$(date -u +%Y%m%dT%H%M%SZ)}-${GITHUB_RUN_ATTEMPT:-1} -->")' \
  "$LIB/../skills/review/SKILL.md"
assert_pin_unique "#356 marker: devflow-review.yml rebuilds the identical run-keyed marker" \
  'FLIP_MARKER="<!-- devflow:review-progress run=${GITHUB_RUN_ID}-${GITHUB_RUN_ATTEMPT} -->"' "$M356_REVIEW_YML"
assert_pin_unique "#356 marker: devflow.yml rebuilds the identical run-keyed marker" \
  'FLIP_MARKER="<!-- devflow:review-progress run=${GITHUB_RUN_ID}-${GITHUB_RUN_ATTEMPT} -->"' "$M356_DEVFLOW_YML"
# Cross-file identity: the two consumers must agree byte-for-byte with each other, and both
# must carry the marker PREFIX the skill seeds. A rename of `devflow:review-progress` on
# either side now goes RED here rather than silently disabling the flip in production.
assert_eq "#356 marker: both workflows' FLIP_MARKER literals are byte-identical" "yes" \
  "$([ "$(grep -oF 'FLIP_MARKER="<!-- devflow:review-progress run=${GITHUB_RUN_ID}-${GITHUB_RUN_ATTEMPT} -->"' "$M356_REVIEW_YML")" \
     = "$(grep -oF 'FLIP_MARKER="<!-- devflow:review-progress run=${GITHUB_RUN_ID}-${GITHUB_RUN_ATTEMPT} -->"' "$M356_DEVFLOW_YML")" ] \
     && [ -n "$(grep -oF 'FLIP_MARKER="<!-- devflow:review-progress run=' "$M356_REVIEW_YML")" ] && echo yes || echo no)"
assert_eq "#356 marker: the marker prefix the skill seeds is the prefix both workflows rebuild" "yes" \
  "$(grep -qF '<!-- devflow:review-progress run=' "$LIB/../skills/review/SKILL.md" \
     && grep -qF '<!-- devflow:review-progress run=' "$M356_REVIEW_YML" \
     && grep -qF '<!-- devflow:review-progress run=' "$M356_DEVFLOW_YML" && echo yes || echo no)"

# ── fetch-pr-context.sh glyph-strip pin (unit) ────────────────────────────────
assert_eq "#356: fetch-pr-context.sh strips 💥 from the workpad Status glyph set" "yes" \
  "$(grep -q '🚀|🎉|👎|💥' "$LIB/fetch-pr-context.sh" && echo yes || echo no)"

# ── Static workflow-wiring pins (the repo's #232/#258 pattern) ─────────────────
IMPL_YML="$LIB/../.github/workflows/devflow-implement.yml"
REVIEW_YML="$LIB/../.github/workflows/devflow-review.yml"
DEVFLOW_YML="$LIB/../.github/workflows/devflow.yml"

# #450 coupled-mirror pin: matcher-probe.yml's implement-probe job hand-copies
# devflow-implement.yml's baked --allowed-tools TOOLS literal into its IMPLEMENT='…'
# compose var (a deliberate second copy so the probe measures the REAL implement
# profile, like the review probe's REVIEW literal). A drift between the two would make
# the probe silently measure a stale profile, so assert comma-split token-list identity
# (order + content) here — the repo's coupled-mirror discipline applied to the new mirror
# site. The two literals are NOT byte-identical (the baked one is newline+indent-wrapped,
# the probe copy single-line); the extractor flattens
# both literals to comma-split tokens and compares order + content; it prints DRIFT (fail)
# on any divergence and EXTRACT-FAIL if either literal can't be located.
MPROBE_YML="$LIB/../.github/workflows/matcher-probe.yml"
assert_eq "#450 pin: matcher-probe IMPLEMENT literal is token-synced with devflow-implement.yml TOOLS" "SYNCED" \
  "$(python3 -c '
import re,sys
b=re.search(r"--allowed-tools\s*\n\s*\"(.*?)Bash\(tee:\*\)\$\{\{", open(sys.argv[1]).read(), re.S)
p=re.search(r"IMPLEMENT=\x27(.*?)\x27", open(sys.argv[2]).read(), re.S)
if not b or not p:
    print("EXTRACT-FAIL"); sys.exit(0)
bt=[t.strip() for t in (b.group(1)+"Bash(tee:*)").split(",") if t.strip()]
pt=[t.strip() for t in p.group(1).split(",") if t.strip()]
print("SYNCED" if bt==pt else "DRIFT")
' "$IMPL_YML" "$MPROBE_YML")"

# Implement flip: the function + each of its fail-loud call sites (at least the four
# pinned below), guarded on interim. Each pin quotes that site's unique cause string,
# so deleting the call goes RED; a fifth site added later never falsifies this prose.
assert_eq "#356 pin: devflow-implement.yml defines flip_to_failed guarded on CLASS=interim" "yes" \
  "$(grep -q 'flip_to_failed()' "$IMPL_YML" && grep -q '\[ "\${CLASS:-}" = "interim" \] || return 0' "$IMPL_YML" && echo yes || echo no)"
assert_eq "#356 pin: implement flip writes --status Failed with a dead-run note" "yes" \
  "$(grep -q -- '--status Failed' "$IMPL_YML" && grep -q 'run died:' "$IMPL_YML" && echo yes || echo no)"
assert_eq "#356 pin: implement flip called at the mktemp abort" "yes" \
  "$(grep -q 'flip_to_failed "mktemp failed' "$IMPL_YML" && echo yes || echo no)"
assert_eq "#356 pin: implement flip called at the dropped-resume-comment abort" "yes" \
  "$(grep -q 'flip_to_failed "resume re-dispatch comment did not land"' "$IMPL_YML" && echo yes || echo no)"
assert_eq "#356 pin: implement flip called at the resume-posted-but-no-App-token abort" "yes" \
  "$(grep -q 'flip_to_failed "resume comment posted but no App token' "$IMPL_YML" && echo yes || echo no)"
assert_eq "#356 pin: implement flip at the shared final exit is guarded FAIL=1 (never the green resume)" "yes" \
  "$(grep -q '\[ "\$FAIL" -eq 1 \] && flip_to_failed "\${DECISION}"' "$IMPL_YML" && echo yes || echo no)"
# Absence: the flip must NOT sit inside the resume-comment case arm (the green path) —
# writing a terminal Failed before a resume would make the resumed run's own backstop
# read `terminal -> noop` and permanently disarm it. This is THE load-bearing invariant.
#
# The range is located indentation-AGNOSTICALLY, and the arm's body is asserted
# non-empty FIRST. A range keyed on literal indentation fails OPEN on any reflow of the
# `case` block: the range never opens, awk prints nothing, and the absence check reports
# PASS while the regression sits in the arm. The positive control below turns that
# vacuous-range case RED instead — an absence pin that cannot locate its subject asserts
# nothing, so it must fail, not pass.
_resume_arm_body() {  # print the lines strictly inside the `resume)` case arm
  awk '
    /^[[:space:]]*resume\)[[:space:]]*$/ { f=1; next }
    f && /^[[:space:]]*;;[[:space:]]*$/  { f=0; next }
    f { print }
  ' "$1"
}
assert_eq "#356 pin: the resume) case arm is locatable (absence pin below is not vacuous)" "yes" \
  "$([ -n "$(_resume_arm_body "$IMPL_YML")" ] && echo yes || echo no)"
assert_eq "#356 pin: no flip_to_failed inside the resume) comment-building case arm" "yes" \
  "$(_resume_arm_body "$IMPL_YML" | grep -q 'flip_to_failed' && echo no || echo yes)"

# The flip step names the specific arm that fired, so the comment's cause line and the
# job log agree on why the run was treated as dead. Pin both cause strings.
assert_eq "#356 pin: devflow.yml names the engine-error cause when is_error fired on a success step" "yes" \
  "$(grep -qF 'CAUSE="review engine ended with an error (is_error)"' "$DEVFLOW_YML" && echo yes || echo no)"
assert_eq "#356 pin: devflow.yml otherwise names the claude step outcome as the cause" "yes" \
  "$(grep -qF 'CAUSE="claude step ${CLAUDE_OUTCOME}"' "$DEVFLOW_YML" && echo yes || echo no)"

# Review flip: finalize_check's three arms + devflow.yml's outcome-keyed step.
assert_eq "#356 pin: devflow-review.yml finalize_check invokes flip_review on job failure" "yes" \
  "$(grep -q 'flip_review "review job failed' "$REVIEW_YML" && echo yes || echo no)"
assert_eq "#356 pin: devflow-review.yml finalize_check invokes flip_review on cancellation" "yes" \
  "$(grep -q 'flip_review "review job cancelled"' "$REVIEW_YML" && echo yes || echo no)"
# The engine-error arm is GATED on ENGINE_ERROR so a plain no-verdict incomplete —
# where the agent ran to completion and wrote its own verdict — is left to the agent.
# A file-wide `grep -q 'ENGINE_ERROR:-false'` does NOT pin that gate: the literal also
# occurs in a prose comment and on the DERIVED= line, so deleting the `if` guard while
# keeping the flip_review call leaves such a pin GREEN while the flip starts firing on
# every incomplete. Pin the guard CO-LOCATED with the call it gates instead: extract the
# guard line and the line that follows it, and require the call to sit inside. The
# positive control below asserts the extracted window is non-empty first, so a guard that
# is reworded (and thus no longer locatable) fails RED rather than passing vacuously.
_engine_error_guard_window() {  # print the ENGINE_ERROR guard line + the line after it
  grep -A1 -F 'if [ "${ENGINE_ERROR:-false}" = "true" ]; then' "$1"
}
assert_eq "#356 pin: the ENGINE_ERROR guard is locatable (co-location pin below is not vacuous)" "yes" \
  "$([ -n "$(_engine_error_guard_window "$REVIEW_YML")" ] && echo yes || echo no)"
assert_eq "#356 pin: devflow-review.yml finalize_check invokes flip_review on engine-error incomplete" "yes" \
  "$(_engine_error_guard_window "$REVIEW_YML" | grep -q 'flip_review "review engine ended with an error' && echo yes || echo no)"
assert_eq "#356 pin: devflow-review.yml wires flip-review-progress-failed.sh" "yes" \
  "$(grep -q 'flip-review-progress-failed.sh' "$REVIEW_YML" && echo yes || echo no)"
# The filename alone also appears on the FLIP_HELPER= path-assignment lines, so a
# filename-only pin stays GREEN even if the INVOCATION is deleted (gutting the flip).
# Pin the invocation itself, in each workflow.
assert_eq "#356 pin: devflow-review.yml actually INVOKES the helper (not just names it)" "yes" \
  "$(grep -qF 'bash "$FLIP_HELPER" "$PR_NUMBER" "$FLIP_MARKER"' "$REVIEW_YML" && echo yes || echo no)"
assert_eq "#356 pin: devflow.yml adds the dead-run review-progress flip step" "yes" \
  "$(grep -q 'Flip review-progress comment on dead run' "$DEVFLOW_YML" && echo yes || echo no)"
assert_eq "#356 pin: devflow.yml flip step wires the helper" "yes" \
  "$(grep -q 'flip-review-progress-failed.sh' "$DEVFLOW_YML" && echo yes || echo no)"
assert_eq "#356 pin: devflow.yml actually INVOKES the helper (not just names it)" "yes" \
  "$(grep -qF 'bash "$FLIP_HELPER" "$CONTEXT_NUMBER" "$FLIP_MARKER"' "$DEVFLOW_YML" && echo yes || echo no)"
# Per-DISJUNCT pins on the flip step's `if:` guard. A bare `grep steps.claude.outcome`
# would also match the step's own `CLAUDE_OUTCOME:` env line, so deleting a disjunct
# from the guard would leave it GREEN — the exact vacuous-pin failure these replace.
# Each pin below quotes the whole comparison, so removing any one arm goes RED.
# The guard is extracted once (the single `if:` line carrying `always()`), so a
# comparison appearing anywhere else in the file cannot satisfy these.
DF356_IF="$(grep -F 'if: ${{ always() && (steps.claude.outcome' "$DEVFLOW_YML" || true)"
assert_eq "#356 pin: devflow.yml flip step fires on a FAILED claude step" "yes" \
  "$(printf '%s' "$DF356_IF" | grep -qF "steps.claude.outcome == 'failure'" && echo yes || echo no)"
assert_eq "#356 pin: devflow.yml flip step fires on a CANCELLED claude step" "yes" \
  "$(printf '%s' "$DF356_IF" | grep -qF "steps.claude.outcome == 'cancelled'" && echo yes || echo no)"
assert_eq "#356 pin: devflow.yml flip step fires when the engine ended is_error" "yes" \
  "$(printf '%s' "$DF356_IF" | grep -qF "steps.engine.outputs.is_error == 'true'" && echo yes || echo no)"
assert_eq "#356 pin: devflow.yml flip step's guard is always()-wrapped (runs on cancellation)" "yes" \
  "$(printf '%s' "$DF356_IF" | grep -qF 'always()' && echo yes || echo no)"
# The is_error disjunct needs a producer: devflow.yml must parse the engine result
# into steps.engine, mirroring devflow-runner.yml's own parse step.
assert_eq "#356 pin: devflow.yml surfaces the engine execution result as steps.engine.is_error" "yes" \
  "$(grep -q 'id: engine' "$DEVFLOW_YML" && grep -q 'parse-engine-error.sh' "$DEVFLOW_YML" && grep -q 'is_error=\$IS_ERROR' "$DEVFLOW_YML" && echo yes || echo no)"
rm -rf "$S356"

# ── issue #338: --rewrite-ac (post-merge) retag requires a --note rationale ────
# scripts/workpad.py: an `update` call in which any --rewrite-ac pair APPENDS the
# trailing (post-merge) tag (NEW ends with it after rstrip; neither OLD nor the row
# the pair resolves to already does) and which carries no non-empty --note aborts
# STRUCTURALLY — _UpdateError, exit 1, stderr naming the offending pair, NO PATCH
# issued (all-or-nothing preserved). The same call with a non-empty --note succeeds.
# A pair targeting a row that already ends with the tag, or that removes it, needs no
# note. Exercised as a real CLI subprocess against a gh stub, mirroring the #258
# fixture pattern. T1/T4/T5 go RED against the pre-guard workpad.py (the laundered
# tag PATCHed with no rationale); T2/T3/T3c/T5b are pass controls.
S338="$(mktemp -d)"
cat > "$S338/gh" <<'STUB'
#!/usr/bin/env bash
# Minimal gh stub for workpad.py update: repo view, comments list (marker match),
# body fetch, and PATCH (records that a PATCH happened + echoes the patched body).
j="$*"
if [[ "$j" == *"repo view"* ]]; then echo "owner/repo"; exit 0; fi
if [[ "$j" == *"-X PATCH"* ]]; then
  echo p >> "$WP_PATCHLOG"
  for a in "$@"; do case "$a" in body=@*) cat "${a#body=@}";; esac; done
  exit 0
fi
if [[ "$j" == *"issues/comments/7"* ]]; then cat "$WP_BODY"; exit 0; fi
if [[ "$j" == *"issues/999/comments"* ]]; then echo '[{"id":7,"body":"<!-- devflow:workpad -->"}]'; exit 0; fi
echo '[]'
STUB
chmod +x "$S338/gh"

cat > "$S338/base.md" <<'WPMD'
<!-- devflow:workpad -->
# DevFlow Workpad — Issue #999

**Status:** 🚀 Reviewing
**Last updated:** 2026-05-15T00:00:00Z

## Progress
- [ ] **Review**

## Plan
- [x] Plan step one

## Acceptance Criteria
- [ ] AC one
- [ ] AC two
WPMD
# A fixture whose AC two already carries the (post-merge) tag (for the OLD-already-tagged case).
sed 's/- \[ \] AC two/- [ ] AC two (post-merge)/' "$S338/base.md" > "$S338/base-tagged.md"
# A fixture carrying a `## Devflow Reflection` section, so a --reflection is a VALID
# mutation on it. Without that section --reflection aborts on 'section not found', and a
# test asserting "a reflection does not satisfy the --note" would pass for that unrelated
# reason — staying green against a mutant that lets a reflection satisfy the guard (T4d).
cp "$S338/base.md" "$S338/base-refl.md"
printf '\n## Devflow Reflection\n- existing bullet\n' >> "$S338/base-refl.md"
# A fixture whose AC two is already TICKED (`- [x]`). The retag guards must treat a
# ticked row's tag exactly like an unticked one: `- [x]` rows are outside the Phase 3.4
# terminal gate's population, but a `(post-merge)` tag landing on one is still a net-added
# tagged row, and SKILL.md/DEVFLOW_SYSTEM_OVERVIEW both promise a crafted multi-pair
# sequence that net-adds such a row is caught.
sed 's/- \[ \] AC two/- [x] AC two/' "$S338/base.md" > "$S338/base-ticked.md"
# ...and one whose ticked AC two is already tagged (for the tag-preserving no-false-fire control).
sed 's/- \[ \] AC two/- [x] AC two (post-merge)/' "$S338/base.md" > "$S338/base-ticked-tagged.md"

# run338 <body-file> <args...> → prints the exit code; leaves out/err/patchlog on disk.
run338() {
  local body="$1"; shift
  : > "$S338/patchlog"
  WP_BODY="$body" WP_PATCHLOG="$S338/patchlog" DEVFLOW_GH="$S338/gh" \
    python3 "$WP_PY" update 999 "$@" >"$S338/out" 2>"$S338/err"
  echo $?
}

# T1 (refusal — reproduces the defect): appending pair, no --note → abort, NO PATCH.
_c="$(run338 "$S338/base.md" --rewrite-ac "AC two" "AC two (post-merge)")"
assert_eq "#338(T1): appending (post-merge) retag with no --note aborts non-zero" "no" \
  "$([ "$_c" = "0" ] && echo yes || echo no)"
assert_eq "#338(T1): the refusal made NO PATCH (all-or-nothing)" "yes" \
  "$([ -s "$S338/patchlog" ] && echo no || echo yes)"
assert_eq "#338(T1): the refusal names the offending pair on stderr" "yes" \
  "$(grep -q 'AC two' "$S338/err" && grep -q 'post-merge' "$S338/err" && echo yes || echo no)"

# T2 (pass with note): identical call + non-empty --note → exit 0, row rewritten.
_c="$(run338 "$S338/base.md" --rewrite-ac "AC two" "AC two (post-merge)" \
  --note "retro-tagged as post-merge (genuinely-live): live deploy target")"
assert_eq "#338(T2): the same retag WITH a non-empty --note succeeds (exit 0)" "0" "$_c"
assert_eq "#338(T2): the with-note retag PATCHed the row with the (post-merge) tag" "yes" \
  "$([ -s "$S338/patchlog" ] && grep -q '\- \[ \] AC two (post-merge)' "$S338/out" && echo yes || echo no)"

# T2b (note scope is the CALL, not the pair): the guard's documented contract is that ANY
# one non-empty --note in the same update call satisfies it, whether or not the note is
# *about* the retag — the note is appended to ## Progress, never bound to the rewritten
# row, so the guard enforces that a rationale EXISTS for the retrospective auditor to
# read, not that it is true or on-topic. This batched call carries a note describing the
# OTHER pair (the plain AC one rewrite) and never mentions the tag or the retagged row,
# and must still pass. Without this pin a refactor that bound the note to the specific
# appending pair would tighten the contract past what workpad.py's guard comment,
# SKILL.md, and docs/implement-skill.md all promise, while every other S338 test — whose
# notes all happen to describe the retag itself — stayed green. Compare T5: the same
# batched shape with NO note is refused.
_c="$(run338 "$S338/base.md" --rewrite-ac "AC one" "AC one edited" \
  --rewrite-ac "AC two" "AC two (post-merge)" \
  --note "reworded the first criterion for clarity")"
assert_eq "#338(T2b): an appending retag is satisfied by any non-empty --note in the call, even one about an unrelated pair (exit 0)" "0" "$_c"
assert_eq "#338(T2b): the call-scoped-note retag PATCHed the (post-merge) row" "yes" \
  "$([ -s "$S338/patchlog" ] && grep -q '\- \[ \] AC two (post-merge)' "$S338/out" && echo yes || echo no)"
assert_eq "#338(T2b): the unrelated pair in the same call applied too" "yes" \
  "$(grep -q '\- \[ \] AC one edited' "$S338/out" && echo yes || echo no)"

# T3 (no false fire): OLD already ends with the tag → a text tweak needs no note.
_c="$(run338 "$S338/base-tagged.md" --rewrite-ac "AC two (post-merge)" "AC two reworded (post-merge)")"
assert_eq "#338(T3): a rewrite whose OLD already ends with (post-merge) passes with no note (exit 0)" "0" "$_c"
assert_eq "#338(T3): the tag-preserving rewrite PATCHed" "yes" \
  "$([ -s "$S338/patchlog" ] && echo yes || echo no)"

# T4 (empty note): --note "" with an appending pair is a MISSING rationale → refused.
_c="$(run338 "$S338/base.md" --rewrite-ac "AC two" "AC two (post-merge)" --note "")"
assert_eq "#338(T4): an empty-string --note is treated as missing → refused (non-zero)" "no" \
  "$([ "$_c" = "0" ] && echo yes || echo no)"
assert_eq "#338(T4): the empty-note refusal made NO PATCH" "yes" \
  "$([ -s "$S338/patchlog" ] && echo no || echo yes)"

# T5 (all-or-nothing): a mixed repeatable call (one appending pair among a plain
# rewrite), no note, is refused BEFORE any PATCH — no partial application.
_c="$(run338 "$S338/base.md" --rewrite-ac "AC one" "AC one edited" \
  --rewrite-ac "AC two" "AC two (post-merge)")"
assert_eq "#338(T5): a mixed call with one appending pair, no note, aborts non-zero" "no" \
  "$([ "$_c" = "0" ] && echo yes || echo no)"
assert_eq "#338(T5): the mixed-call refusal made NO PATCH (the plain rewrite did not partially apply)" "yes" \
  "$([ -s "$S338/patchlog" ] && echo no || echo yes)"

# T5b (guard + backstop no FALSE FIRE): an ordinary batched multi-pair rewrite that never
# touches the (post-merge) tag needs no note and must apply in full. Pins the innocent
# path both guards share: a regression that miscounted a plain row as post-merge-terminal
# (or classified a plain pair as an append) would abort an honest batch, and no other
# S338 test would notice — every one of them either carries a note or expects a refusal.
_c="$(run338 "$S338/base.md" --rewrite-ac "AC one" "AC one edited" \
  --rewrite-ac "AC two" "AC two edited")"
assert_eq "#338(T5b): an ordinary batched no-note rewrite that never touches the tag succeeds (exit 0)" "0" "$_c"
assert_eq "#338(T5b): both pairs of the innocent batch applied" "yes" \
  "$([ -s "$S338/patchlog" ] && grep -q '\- \[ \] AC one edited' "$S338/out" \
     && grep -q '\- \[ \] AC two edited' "$S338/out" && echo yes || echo no)"

# T3b (removal pair — documented no-note case, unpinned until now): NEW lacks the tag
# and OLD ends with it (de-tagging an already-post-merge row) needs no note. Pins the
# predicate's first-conjunct-False path (no current test drives it: T1/T2/T3 all have NEW
# ending in the marker), so a refactor that fired on any tag *movement* would go RED here.
_c="$(run338 "$S338/base-tagged.md" --rewrite-ac "AC two (post-merge)" "AC two")"
assert_eq "#338(T3b): a rewrite that REMOVES the (post-merge) tag passes with no note (exit 0)" "0" "$_c"
assert_eq "#338(T3b): the tag-removing rewrite PATCHed" "yes" \
  "$([ -s "$S338/patchlog" ] && echo yes || echo no)"

# T3c (no false REFUSAL — the guard reasons over the RESOLVED ROW, not the OLD string):
# a text tweak on a row that ALREADY ends with the tag creates no new deferral, so it
# needs no note — even when the OLD substring does not itself span the tag. The
# argument-string-only predicate classified this as an append and demanded a --note,
# contradicting the exemption workpad.py's docstring, SKILL.md and docs/implement-skill.md
# all publish. Fails CLOSED (an extra-note demand, never a laundered deferral), but the
# published contract must match the code. RED against the OLD-string-only predicate.
_c="$(run338 "$S338/base-tagged.md" --rewrite-ac "AC two" "AC two clarified (post-merge)")"
assert_eq "#338(T3c): a tweak on an already-(post-merge) row needs no note even when OLD omits the tag (exit 0)" "0" "$_c"
assert_eq "#338(T3c): the already-tagged-row tweak PATCHed the reworded row" "yes" \
  "$([ -s "$S338/patchlog" ] && grep -q '\- \[ \] AC two clarified (post-merge)' "$S338/out" && echo yes || echo no)"
# Control: the SAME shape onto an UNTAGGED row is still refused — the exemption is bound
# to the target row's existing tag, not to the OLD substring being a prefix.
_c="$(run338 "$S338/base-tagged.md" --rewrite-ac "AC one" "AC one clarified (post-merge)")"
assert_eq "#338(T3c): the same shape onto an UNTAGGED row is still refused (non-zero)" "no" \
  "$([ "$_c" = "0" ] && echo yes || echo no)"
assert_eq "#338(T3c): the untagged-row refusal made NO PATCH" "yes" \
  "$([ -s "$S338/patchlog" ] && echo no || echo yes)"

# T4b (trailing-whitespace anti-evasion — the reason the predicate rstrips): an appending
# pair whose NEW ends with the tag plus trailing spaces is still an append and is refused
# with no note. Pins the rstrip; a bare endswith (no rstrip) would let this evasion through
# while every other S338 test stayed green.
_c="$(run338 "$S338/base.md" --rewrite-ac "AC two" "AC two (post-merge)   ")"
assert_eq "#338(T4b): an appending pair with trailing whitespace after the tag is refused (non-zero)" "no" \
  "$([ "$_c" = "0" ] && echo yes || echo no)"
assert_eq "#338(T4b): the trailing-whitespace-append refusal made NO PATCH" "yes" \
  "$([ -s "$S338/patchlog" ] && echo no || echo yes)"

# T4c (note-side anti-evasion — the discriminating input that actually pins `.strip()`):
# T4's `--note ""` does NOT pin it — `any([""])` is already falsy, so T4 stays GREEN
# against a mutant `has_note = any(n for n in args.note)`. A whitespace-only note is the
# input that separates them: truthy as a bare string, falsy after `.strip()`. Mutation-
# checked — dropping `.strip()` turns THIS assertion RED while T4 stays GREEN.
_c="$(run338 "$S338/base.md" --rewrite-ac "AC two" "AC two (post-merge)" --note "   ")"
assert_eq "#338(T4c): a whitespace-only --note is treated as missing → refused (non-zero)" "no" \
  "$([ "$_c" = "0" ] && echo yes || echo no)"
assert_eq "#338(T4c): the whitespace-note refusal made NO PATCH" "yes" \
  "$([ -s "$S338/patchlog" ] && echo no || echo yes)"

# T4d (only --note satisfies the rationale): a --reflection is a different channel
# (## Devflow Reflection) and never stands in for the retag rationale. Without this pin a
# refactor broadening has_note to accept a reflection would loosen the contract while
# every other S338 test stayed green. Runs against base-refl.md — the fixture that HAS a
# ## Devflow Reflection section — so the reflection is a valid mutation and the refusal is
# attributable to the guard; on a section-less fixture this test would pass vacuously via
# 'section not found'. The stderr assertion pins that attribution (cf. T7's 'net-adds').
_c="$(run338 "$S338/base-refl.md" --rewrite-ac "AC two" "AC two (post-merge)" \
  --reflection "retro-tagged as post-merge (genuinely-live): live deploy target")"
assert_eq "#338(T4d): a --reflection does not satisfy the --note rationale → refused (non-zero)" "no" \
  "$([ "$_c" = "0" ] && echo yes || echo no)"
assert_eq "#338(T4d): the reflection-only refusal made NO PATCH" "yes" \
  "$([ -s "$S338/patchlog" ] && echo no || echo yes)"
assert_eq "#338(T4d): the refusal is the rationale guard's, not an incidental section abort" "yes" \
  "$(grep -q 'no non-empty --note rationale' "$S338/err" && echo yes || echo no)"
# Control: the same call on the same fixture WITH a --note succeeds — proving base-refl.md
# is not itself the reason T4d is refused (the reflection applies cleanly alongside).
_c="$(run338 "$S338/base-refl.md" --rewrite-ac "AC two" "AC two (post-merge)" \
  --reflection "context bullet" --note "genuinely-live: live deploy target")"
assert_eq "#338(T4d): the same reflection call WITH a --note succeeds (exit 0)" "0" "$_c"

# T7 (state-based multi-pair backstop, issue #338 hardening): a crafted two-pair call whose
# pairs each individually dodge the per-pair guard — pair 1 places the marker non-terminally
# (NEW doesn't end in the tag), pair 2 makes it terminal (OLD ends in the tag) — net-adds a
# (post-merge) row. The per-pair guard alone would fail OPEN here; the post-loop count-of-
# post-merge-rows backstop catches it and aborts before any PATCH. RED against the pre-
# backstop code (the laundered tag PATCHes with no note).
_c="$(run338 "$S338/base.md" --rewrite-ac "AC two" "(post-merge) AC two" \
  --rewrite-ac "(post-merge)" "AC two (post-merge)")"
assert_eq "#338(T7): a multi-pair call that net-adds a (post-merge) row with no note is refused (non-zero)" "no" \
  "$([ "$_c" = "0" ] && echo yes || echo no)"
assert_eq "#338(T7): the multi-pair backstop refusal made NO PATCH (all-or-nothing)" "yes" \
  "$([ -s "$S338/patchlog" ] && echo no || echo yes)"
# Assert the refusal came from the STATE BACKSTOP ('net-adds'), not an incidental
# _rewrite_checkbox zero/multi-match abort — so a refactor that made this call fail for
# the wrong reason (while the backstop silently rotted) is caught, not masked by T7b.
assert_eq "#338(T7): the refusal is the state backstop's 'net-adds' abort, not an incidental match failure" "yes" \
  "$(grep -q 'net-adds' "$S338/err" && echo yes || echo no)"
# T7b (backstop no false fire): the identical multi-pair call WITH a non-empty --note succeeds.
_c="$(run338 "$S338/base.md" --rewrite-ac "AC two" "(post-merge) AC two" \
  --rewrite-ac "(post-merge)" "AC two (post-merge)" --note "retro-tagged (genuinely-live): live endpoint")"
assert_eq "#338(T7b): the same multi-pair retag WITH a --note succeeds (exit 0)" "0" "$_c"

# T8 (single-pair append onto an already-TICKED row): the per-pair guard is tick-state
# agnostic — it reasons over the row's LABEL text, which `_CHECKBOX_ROW_RE` exposes
# independently of the `[ ]`/`[x]` state cell — so this is refused with no note. Behavior
# was already correct but unpinned; without this a refactor that skipped `[x]` rows in the
# per-pair guard (to "match" the backstop's old unticked-only population) would go
# unnoticed by every other S338 test, all of which drive `- [ ]` rows.
#
# ATTRIBUTION IS LOAD-BEARING HERE, not decoration. Since the backstop now also counts
# ticked rows, a mutant that skips `[x]` rows in the per-pair guard STILL exits non-zero
# with no PATCH — the backstop catches it one step later. rc/no-PATCH assertions alone
# therefore pass on the very mutant this test exists to kill. Pin the refusal to the
# PER-PAIR guard: its message names the offending pair, and it never says `net-adds` (the
# backstop's word). Both attribution assertions below independently kill that mutant — the
# backstop's message omits the pair AND says `net-adds` — while the rc/no-PATCH assertions
# alone stay GREEN on it. Note the backstop's message also contains the phrase
# `no non-empty --note rationale`, so that substring alone does not discriminate; the
# pair name is what does.
_c="$(run338 "$S338/base-ticked.md" --rewrite-ac "AC two" "AC two (post-merge)")"
assert_eq "#338(T8): a single-pair (post-merge) append onto a TICKED [x] row is refused (non-zero)" "no" \
  "$([ "$_c" = "0" ] && echo yes || echo no)"
assert_eq "#338(T8): the ticked-row single-pair refusal made NO PATCH" "yes" \
  "$([ -s "$S338/patchlog" ] && echo no || echo yes)"
assert_eq "#338(T8): the refusal is the PER-PAIR guard's (names the pair + rationale), not the backstop's" "yes" \
  "$(grep -q 'AC two' "$S338/err" && grep -q 'no non-empty --note rationale' "$S338/err" && echo yes || echo no)"
assert_eq "#338(T8): the per-pair guard — not the state backstop — refused (stderr has no 'net-adds')" "yes" \
  "$(grep -q 'net-adds' "$S338/err" && echo no || echo yes)"

# T8b (the ticked-row SHUTTLE — the fail-open this backstop population closes): the same
# crafted two-pair shuttle as T7, aimed at an already-`[x]` row. Both pairs dodge the
# per-pair guard exactly as in T7; with the backstop counting only UNTICKED rows the
# tagged row landed with NO note and exit 0, silently falsifying SKILL.md's and
# DEVFLOW_SYSTEM_OVERVIEW's promise that "a crafted multi-pair sequence that net-adds a
# (post-merge) row is caught by the same rule". Snapshotting each row's post-merge-terminal
# flag across EVERY tick state (`_post_merge_flags`) closes it. RED against the
# unticked-only population; the 'net-adds' grep pins that the STATE BACKSTOP is what
# refuses it (T8 already covers the per-pair path, so a refusal for the wrong reason would
# otherwise pass here).
_c="$(run338 "$S338/base-ticked.md" --rewrite-ac "AC two" "(post-merge) AC two" \
  --rewrite-ac "(post-merge)" "AC two (post-merge)")"
assert_eq "#338(T8b): a multi-pair shuttle that net-adds (post-merge) onto a TICKED row is refused (non-zero)" "no" \
  "$([ "$_c" = "0" ] && echo yes || echo no)"
assert_eq "#338(T8b): the ticked-row shuttle refusal made NO PATCH (all-or-nothing)" "yes" \
  "$([ -s "$S338/patchlog" ] && echo no || echo yes)"
assert_eq "#338(T8b): the ticked-row shuttle refusal is the state backstop's 'net-adds' abort" "yes" \
  "$(grep -q 'net-adds' "$S338/err" && echo yes || echo no)"
# T8c (no false fire on the widened population): a tag-PRESERVING tweak on an already-tagged
# TICKED row adds no tagged row, so the wider count must not fire — this is the assertion a
# naive "count every tagged row and abort on any tagged row present" backstop would fail.
_c="$(run338 "$S338/base-ticked-tagged.md" --rewrite-ac "AC two (post-merge)" "AC two reworded (post-merge)")"
assert_eq "#338(T8c): a tag-preserving tweak on a TICKED tagged row still passes with no note (exit 0)" "0" "$_c"
assert_eq "#338(T8c): the ticked tag-preserving rewrite PATCHed" "yes" \
  "$([ -s "$S338/patchlog" ] && echo yes || echo no)"
# T8d (no false fire): REMOVING the tag from a ticked tagged row decreases the count → passes.
_c="$(run338 "$S338/base-ticked-tagged.md" --rewrite-ac "AC two (post-merge)" "AC two")"
assert_eq "#338(T8d): removing the tag from a TICKED row passes with no note (exit 0)" "0" "$_c"

# T9 (net-zero tag-swap — the last laundering shape): remove the tag from one row while
# shuttling it onto ANOTHER, with no note. Every pair dodges the per-pair guard (pair 1
# removes; pair 2's NEW is non-terminal; pair 3's OLD ends with the tag), and the TOTAL
# count of tagged rows is unchanged — so an aggregate-count backstop reads "no net add"
# and PATCHes a silently-deferred criterion. Comparing each row's flag POSITIONALLY
# catches it: AC one transitions untagged -> terminally-tagged. RED against a count-based
# backstop (verified: it exits 0 and PATCHes `- [ ] AC one (post-merge)`).
_c="$(run338 "$S338/base-tagged.md" --rewrite-ac "AC two (post-merge)" "AC two" \
  --rewrite-ac "AC one" "(post-merge) AC one" \
  --rewrite-ac "(post-merge)" "AC one (post-merge)")"
assert_eq "#338(T9): a net-zero tag-swap onto another row is refused (non-zero)" "no" \
  "$([ "$_c" = "0" ] && echo yes || echo no)"
assert_eq "#338(T9): the net-zero tag-swap refusal made NO PATCH (all-or-nothing)" "yes" \
  "$([ -s "$S338/patchlog" ] && echo no || echo yes)"
assert_eq "#338(T9): the net-zero refusal is the state backstop's 'net-adds' abort" "yes" \
  "$(grep -q 'net-adds' "$S338/err" && echo yes || echo no)"
# T9b (no false fire): the identical net-zero swap WITH a --note succeeds.
_c="$(run338 "$S338/base-tagged.md" --rewrite-ac "AC two (post-merge)" "AC two" \
  --rewrite-ac "AC one" "(post-merge) AC one" \
  --rewrite-ac "(post-merge)" "AC one (post-merge)" \
  --note "moved the deferral: AC one needs the live endpoint, AC two was verified")"
assert_eq "#338(T9b): the same net-zero swap WITH a --note succeeds (exit 0)" "0" "$_c"

# T10 (newline in NEW — the premise the positional comparison rests on): `_rewrite_checkbox`
# writes NEW verbatim into ONE line, so an embedded newline splits that checkbox row in two.
# That injects an unreviewed AC row AND breaks the row-index stability `_net_adds_post_merge`
# compares against. It also slips the per-pair guard, whose `NEW ends with the marker` test
# reads the whole string (`X (post-merge)\n- [ ] Y` ends with `Y`). Reject it structurally,
# note or not. RED against the pre-fix code, which exited 0 and PATCHed the injected row.
_c="$(run338 "$S338/base.md" --rewrite-ac "AC two" 'AC two (post-merge)
- [ ] Injected')"
assert_eq "#338(T10): a --rewrite-ac NEW containing a line break is refused (non-zero)" "no" \
  "$([ "$_c" = "0" ] && echo yes || echo no)"
assert_eq "#338(T10): the line-break refusal made NO PATCH (no row injected)" "yes" \
  "$([ -s "$S338/patchlog" ] && echo no || echo yes)"
assert_eq "#338(T10): the refusal names the line boundary, not the missing note" "yes" \
  "$(grep -q 'line boundary in NEW' "$S338/err" && echo yes || echo no)"
# T10a (the full `str.splitlines()` separator set — the superset bug): a `'\n' in s or
# '\r' in s` membership test accepts \v, \f, \x1c-\x1e, NEL, LS and PS, EVERY one of which
# `str.splitlines()` still splits on — so each injected a phantom `- [x]` row (with a
# --note, both post-merge guards are skipped, leaving the row check as the only defense).
# `_is_single_line` shares splitlines' own contract, so the rejected set matches exactly.
# Driven with a --note so a refusal cannot come from a post-merge guard. RED against the
# two-character membership test (all eight exited 0 and PATCHed an injected row).
# Interpreter note: `printf '%b'` must expand `\302\205` (NEL), `\342\200\250` (LS) and
# `\342\200\251` (PS) to their real bytes for the last three cases to drive a separator at
# all. Bash's printf does; zsh's does not — it emits the literal backslash text, which
# carries no separator, so workpad.py would accept the rewrite (exit 0) and these
# assertions would FAIL LOUDLY. They cannot degrade into a silent green. This suite's
# shebang is `#!/usr/bin/env bash`, so the expansion holds. Independently verified: under a
# membership-test mutant all eight — including these three — go RED, which they could not
# if their input carried no separator.
for _sep in '\v' '\f' '\034' '\035' '\036' '\302\205' '\342\200\250' '\342\200\251'; do
  _new="$(printf 'AC two (post-merge)%b- [x] Phantom' "$_sep")"
  _c="$(run338 "$S338/base.md" --rewrite-ac "AC two" "$_new" --note "genuinely-live: endpoint")"
  assert_eq "#338(T10a): NEW split by separator '$_sep' is refused even with a --note" "no" \
    "$([ "$_c" = "0" ] && echo yes || echo no)"
  assert_eq "#338(T10a): separator '$_sep' injected no row (NO PATCH)" "yes" \
    "$([ -s "$S338/patchlog" ] && echo no || echo yes)"
done
# T10b: a --note does NOT excuse it — the newline is a malformed argument, not a deferral.
_c="$(run338 "$S338/base.md" --rewrite-ac "AC two" 'AC two (post-merge)
- [ ] Injected' --note "genuinely-live: live endpoint")"
assert_eq "#338(T10b): a line break in NEW is refused even WITH a --note (non-zero)" "no" \
  "$([ "$_c" = "0" ] && echo yes || echo no)"
# T10c (the laundering combo the newline enabled): remove a tag from one row while
# newline-splitting another into a terminally-tagged row. Row counts differ, so an
# aggregate-count fallback reads the sum as flat and passes. Refused now — first by the
# newline check; and were that ever removed, _net_adds_post_merge's length-mismatch branch
# fails CLOSED rather than downgrading to the blind aggregate compare.
_c="$(run338 "$S338/base-tagged.md" --rewrite-ac "AC two (post-merge)" "AC two" \
  --rewrite-ac "AC one" 'AC one (post-merge)
- [ ] Injected')"
assert_eq "#338(T10c): a newline-split net-zero laundering combo is refused (non-zero)" "no" \
  "$([ "$_c" = "0" ] && echo yes || echo no)"
assert_eq "#338(T10c): the laundering combo made NO PATCH" "yes" \
