# ── issue #476: §1.6 clean-arm records re-route to `--note`; findings re-kind. ──
# The audit's clean/confirm arms no longer emit reflections (the attestation noise
# that tripped the retrospective cheap gate on every clean run) — each records a
# `## Progress` --note the moment its pass completes. Only FINDINGS reflect now: a
# wrong issue claim (issue-accuracy), punted work (deferred), or a hard stop
# (blocked). Pin each property per-arm.
# (a) Absence: §1.6 (the LAST section of phase-1-setup.md) carries ZERO
#     `--reflection-kind note` — that kind was the exclusive clean-arm marker, so a
#     count of 0 proves every clean arm routed to `--note`. The 1.4
#     freshness/resume/checkpoint `--reflection-kind note` arms live ABOVE §1.6 and
#     stay unchanged, which is exactly why this pin slices the section first (a
#     whole-file count would never reach 0). The slice is the same awk technique the
#     #325 freshness-guard pin above uses.
#     NON-VACUITY GUARD (else the absence assertion fails OPEN): if the
#     `### 1.6 Issue-Claim Audit` heading ever drifts, the awk pattern matches
#     nothing, the slice is EMPTY, and `pin_count … == 0` would pass vacuously —
#     silently retiring the guard. So first assert the slice positively captured the
#     region (the heading present once, and a known clean-arm `--note` line present),
#     making the "count 0" a proven delta over a non-empty slice, not an absolute
#     over a possibly-empty input (issue #476 review; same discipline as commit
#     7f7161a's absence-pin non-vacuity proof).
P1_16_SLICE="$(probe_tmp "#476: slice §1.6 for the clean-arm-reflection absence pin")"
awk '/^### 1\.6 Issue-Claim Audit/{f=1} f' "$P1_FILE" > "$P1_16_SLICE"
assert_eq "#476: §1.6 slice non-vacuity — the audit heading was captured (slice is not empty)" "1" \
  "$(pin_count '### 1.6 Issue-Claim Audit' "$P1_16_SLICE")"
assert_eq "#476: §1.6 slice non-vacuity — a clean-arm --note line is present in the slice" "1" \
  "$(pin_count '--note "issue-claim audit (count): no count or enumeration claims found' "$P1_16_SLICE")"
assert_eq "#476: §1.6 has no clean-arm --reflection-kind note (clean confirmations route to --note)" "0" \
  "$(pin_count '--reflection-kind note' "$P1_16_SLICE")"
rm -f "$P1_16_SLICE"
# (b) The issue-accuracy finding arms — Pass 1 counts-differ and Pass 2
#     wrong-exclusion (both are feedback that the issue's own claim was wrong).
assert_pin_unique "#476: Pass 1 counts-differ arm records via --reflection-kind issue-accuracy" \
  '--reflection-kind issue-accuracy --reflection "issue-claim audit (count):' "$P1_FILE"
assert_pin_unique "#476: Pass 2 wrong-exclusion arm records via --reflection-kind issue-accuracy" \
  '--reflection-kind issue-accuracy --reflection "issue-claim audit (negative-scope): issue excluded' "$P1_FILE"
# (c) A representative clean arm records via --note (the counts-match arm; distinct
#     from the counts-differ issue-accuracy arm above, so it proves the split landed).
assert_pin_unique "#476: Pass 1 counts-match arm records a clean confirmation via --note" \
  '--note "issue-claim audit (count): claimed '"'"'{N} X'"'"', verified '"'"'{M}'"'"' at HEAD"' "$P1_FILE"
# ── #350 review fixes: re-key the deferral on CREDENTIAL CAPABILITY, and make the
# signal observable + the guard complete. Coupled sites for this ONE change:
#   (1) phase-1 Pass 5 + phase-2 2.2.5/2.5 prose (keyed on cloud AND DEVFLOW_APP_ID empty),
#   (2) the 2.5 guard reverts files COUPLED to a reverted workflow (Important-1),
#   (3) devflow-implement.yml EXPORTS DEVFLOW_APP_ID into the claude step's env so the
#       Phase 1.6 pass can actually read the operand it now keys on (producer for the guard).
IMPL_YML="$LIB/../.github/workflows/devflow-implement.yml"
assert_pin_unique "#350: 2.2.5 exempts a cloud run with DEVFLOW_APP_ID set (workflow-capable App token)" \
  'a cloud run with `DEVFLOW_APP_ID` **set** carries a workflow-capable App token seeded into checkout' "$IMPL_PHASES_DIR/phase-2-implement.md"
assert_pin_unique "#350: Phase 2.5 guard keys on the same cloud + DEVFLOW_APP_ID-empty condition as Pass 5" \
  'the same condition Pass 5 keys on: cloud tier (`GITHUB_ACTIONS=true`) with `DEVFLOW_APP_ID` empty/unset' "$IMPL_PHASES_DIR/phase-2-implement.md"
assert_pin_unique "#350 (Important-1): Phase 2.5 guard reverts files coupled to a reverted workflow (else CI-red)" \
  'revert every file coupled to it in the same step' "$IMPL_PHASES_DIR/phase-2-implement.md"
assert_pin_unique "#350: devflow-implement.yml exports DEVFLOW_APP_ID into the agent env (Pass 5's observable signal)" \
  'DEVFLOW_APP_ID: ${{ vars.DEVFLOW_APP_ID }}' "$IMPL_YML"
# Structurally confirm the export sits inside the 'Run Claude Code' step (between its
# `name:` and its `with:`), so the /devflow:implement agent actually reads it — a bare
# count could pass on a line stranded in the wrong step.
CLAUDE_STEP_BLK="$(awk '/name: Run Claude Code/{f=1} f{print} f&&/^        with:/{exit}' "$IMPL_YML")"
assert_eq "#350: the DEVFLOW_APP_ID env export lives in the Run Claude Code step (before its with:)" "1" \
  "$(printf '%s\n' "$CLAUDE_STEP_BLK" | grep -cF 'DEVFLOW_APP_ID: ${{ vars.DEVFLOW_APP_ID }}')"
# ── issue #185 (+ Addendum): Phase 4.1 Documentation Needed cross-check ─────
# Phase 4.1 enforces named documentation deliverables in two stages:
#   Stage 1 pre-flight: extract the Documentation Needed paths and inject them
#     into the docs subagent dispatch instruction as required deliverables.
#   Stage 2 post-hoc: cross-check each path against the PR diff; self-heal or
#     route to Blocked for absent paths.
# The Addendum (2026-06-29) SUPERSEDES LLM prose-extraction: a deterministic
# helper (scripts/extract-doc-needed-paths.sh) is the single extraction boundary
# BOTH stages consume, and its behavior is verified by the fixture matrix below
# (not by prose pins). The prose pins here lock the load-bearing operative
# sentences of each stage's control flow; they are intentionally NOT a tally,
# so this comment names them structurally rather than by count (a hardcoded
# count drifts the moment an arm is added or removed):
#   Stage 1 — deterministic-extraction mandate + mandatory-deliverable dispatch
#             phrase + present-bullet-but-no-paths audit note.
#   Stage 2 — single-source-of-truth re-run, no-op escape, bare-filename match,
#             self-heal condition, three-dot diff range, Blocked arm, $BASE
#             non-empty fallback, rc-vs-empty-stdout distinction, broken-command
#             fail-closed floor, and remote-anchored self-heal re-check.
assert_pin_unique "#185: Phase 4.1 Stage 1 requires docs subagent to treat named paths as mandatory (D)" \
  'treat each as a mandatory deliverable' "$IMPL_SKILL"
# Addendum: Stage 1 extraction is deterministic (helper), not LLM prose-reading.
assert_pin_unique "#185A: Phase 4.1 Stage 1 mandates deterministic (not LLM) extraction" \
  'do not interpret the prose yourself' "$IMPL_SKILL"
# Addendum: both stages consume the SAME deterministic helper (not re-derived). Issue #284
# folded the once-only retry into each stage's `if ! A && ! B` extractor guard, so the
# helper is now invoked twice per stage (read + retry) × 2 stages = 4 occurrences.
assert_eq "#185A: Phase 4.1 calls extract-doc-needed-paths.sh in BOTH stages (read+retry each)" \
  "4" "$(pin_count 'extract-doc-needed-paths.sh' "$IMPL_SKILL")"
assert_pin_unique "#185A: Phase 4.1 Stage 2 re-runs the helper as the single source of truth" \
  're-running the helper is the single source of truth' "$IMPL_SKILL"
# #190 suggestion 1: a present-but-empty Documentation Needed bullet must leave an
# auditable breadcrumb rather than silently disabling enforcement.
assert_pin_unique "#190: Phase 4.1 Stage 1 records a note when the bullet has no extractable paths (H)" \
  'the extractor found no file paths' "$IMPL_SKILL"
assert_pin_unique "#185: Phase 4.1 Stage 2 no-op escape hatch when no paths extracted (E)" \
  'this cross-check is a no-op' "$IMPL_SKILL"
assert_pin_unique "#185: Phase 4.1 Stage 2 bare-filename matching rule (F)" \
  'whose basename matches it counts as satisfied' "$IMPL_SKILL"
assert_pin_unique "#185: Phase 4.1 Stage 2 keeps the absent-file self-heal condition (A)" \
  'absent from the diff, perform the missing update' "$IMPL_SKILL"
# Issue #284 folded the once-only retry into the Stage-2 diff `if ! A && { fetch; ! B; }`
# guard, so the three-dot range now appears twice (read + retry) — count-based, ==2.
assert_eq "#185: Phase 4.1 Stage 2 uses the three-dot origin/\$BASE...HEAD diff range (B, read+retry)" \
  "2" "$(pin_count 'git diff --name-only "origin/$BASE...HEAD"' "$IMPL_SKILL")"
assert_pin_unique "#185: Phase 4.1 Stage 2 Blocked arm names the missing-content condition (C)" \
  'Documentation Needed file content cannot be determined' "$IMPL_SKILL"
# #190 finding 2: $BASE-empty recovery must mirror the Phase 1.4 fallback, not
# just the config-get.sh read (the read alone returns nothing on malformed config).
assert_pin_unique "#190: Phase 4.1 Stage 2 \$BASE recovery mirrors the Phase 1.4 fallback (I)" \
  'applying its non-empty fallback and not just the config read' "$IMPL_SKILL"
# #190 finding 3 (re-stated per review Critical #2): the FAILURE signal is the exit
# status, never stdout emptiness — an rc-0 empty diff is a genuine all-absent result.
assert_pin_unique "#190: Phase 4.1 Stage 2 distinguishes rc-0 empty stdout from a command failure (J)" \
  'an rc-0 result with empty stdout is NOT a failure' "$IMPL_SKILL"
# Review suggestion 1: a re-fetch that itself fails must fail CLOSED (Blocked),
# never fall through to a path-absent verdict on a broken command.
assert_pin_unique "#190: Phase 4.1 Stage 2 fails closed when the diff command stays broken" \
  'never fall through to a path-absent verdict on a broken command' "$IMPL_SKILL"
# #190 finding 1 (re-stated per review Important #3): the self-heal re-check is
# remote-anchored — HEAD must match @{u}, so a no-op/rejected push cannot satisfy
# the gate off a still-local commit.
assert_pin_unique "#190: Phase 4.1 Stage 2 self-heal re-check is remote-anchored (K)" \
  'the local branch is in sync with its upstream' "$IMPL_SKILL"
# PR #190 fix-loop: the EXTRACTION side (gh issue view / helper) must read the
# exit status, not stdout emptiness — a failed gh issue view (auth/network/wrong
# number) emits empty stdout indistinguishable from a genuinely empty bullet and
# would silently disable the whole gate. Issue #284 migrated this from a captured
# GH_RC/HELPER_RC (which a cross-statement-variable-stripping inline-bash runner
# leaves empty, making the fail-closed check inert) to guards reading each command's
# OWN exit status inline. The #284 SHADOW review then found the interim two-guard form
# still hopped ISSUE_BODY across statements (gh assigned in one statement, read by the
# extractor in the next) — a residual fail-OPEN on a value-stripping runner. The
# fix-delta gate then flagged that a `set -o pipefail`-pipe alternative would rest on
# SHELL-OPTION state surviving between statements inside $(...), the same marshaling class.
# So the body is now passed through a FIXED TEMP FILE: gh writes it (statement 1, if!-guarded
# on gh's own rc), the extractor reads it (statement 2, if!-guarded on the extractor's rc) —
# a literal disk PATH, neither a variable nor an option, so NO marshaled cross-statement
# state has to survive. Assert the temp-file form in BOTH stages (coupled site) and that the
# old captured-rc recipe, the ISSUE_BODY value-hop, AND the pipefail-option form are all GONE.
assert_eq "#284 fix-loop: Phase 4.1 gh body read is if!-guarded in BOTH stages" \
  "2" "$(pin_count 'if ! gh issue view $ISSUE_NUMBER --json body' "$IMPL_SKILL")"
assert_eq "#284 fix-loop: Phase 4.1 gh writes the body to a fixed temp file (read+retry x2 stages)" \
  "4" "$(pin_count '> /tmp/devflow-docgate-body-$ISSUE_NUMBER.txt 2>' "$IMPL_SKILL")"
assert_eq "#284 fix-loop: Phase 4.1 extractor reads that temp file (read+retry x2 stages)" \
  "4" "$(pin_count 'extract-doc-needed-paths.sh < /tmp/devflow-docgate-body-$ISSUE_NUMBER.txt' "$IMPL_SKILL")"
assert_eq "#284 fix-loop: Phase 4.1 no longer carries the old GH_RC/HELPER_RC capture-then-read recipe" \
  "0" "$(pin_count 'GH_RC=$?' "$IMPL_SKILL")"
# The ISSUE_BODY value-hop the shadow flagged, and the pipefail-option form the fix-delta gate
# flagged, must BOTH be GONE — the temp-file form depends on neither.
assert_eq "#284 shadow-fix: Phase 4.1 no longer assigns ISSUE_BODY in a gh guard (value-hop removed)" \
  "0" "$(pin_count 'if ! ISSUE_BODY=$(gh issue view' "$IMPL_SKILL")"
assert_eq "#284 shadow-fix: Phase 4.1 no longer reads ISSUE_BODY across statements into the extractor" \
  "0" "$(pin_count 'printf '"'"'%s'"'"' "$ISSUE_BODY" |' "$IMPL_SKILL")"
assert_eq "#284 delta-gate-fix: Phase 4.1 doc gate does not rest on set -o pipefail option state" \
  "0" "$(pin_count 'set -o pipefail; gh issue view' "$IMPL_SKILL")"
assert_eq "#190 fix-loop: Phase 4.1 fail-closed extraction contract pinned in BOTH stages" \
  "2" "$(pin_count 'never treat its empty stdout as a no-op' "$IMPL_SKILL")"

# ── issue #230: narrative is a starting point; only Desired Behavior + ACs are ──
# authoritative downstream, and the Documentation Needed bullet is a floor-not-a-
# ceiling. These are load-bearing guidance prose, so pin their operative sentences
# in the OWNING phase file directly (not the merged bundle) — AC7 requires a
