  "$([ "$NONJSON_RC" -ne 0 ] && echo true || echo false)"
# --dry-run: records the DRYRUN sentinel, invokes NO issue create / issue edit
echo '{"schema_version":1,"dismissed":{}}' > "$MI_TMP/ov3.json"
cat > "$MI_TMP/gh" <<'STUB'
