TB_DR_DIR="$(mktemp -d)"
printf '{"slug":"pr-9","iterations":2}' > "$TB_DR_DIR/pr-9-good.json"
printf '[1, 2, 3]'                      > "$TB_DR_DIR/pr-9-drift.json"
