DJQ_ROOT="$(cd "$LIB/.." && pwd)"
JQT8="$(mktemp -d)"
mkdir -p "$JQT8/scripts"
cp "$DJQ_ROOT/scripts/detect-project-tools.sh" "$JQT8/scripts/"
T8_ERR="$(bash "$JQT8/scripts/detect-project-tools.sh" "$JQT8" 2>&1 >/dev/null)"; T8_RC=$?
