T9B_ERRLOG="$(DEVFLOW_JQ="$SCVO/broken-jq" PATH="$SCVO" "$_SCV_BASH_BIN" -c "DEVFLOW_SELFTEST=1 . \"$DJQ_ROOT/install.sh\" && set_config_version \"$SCVO/config.json\" beef1234" 2>&1)"
