    "$(grep -qF 'devflow:stall-backstop-audit' "$SB268_POST" && grep -qF '/devflow:implement 5' "$SB268_POST" && echo yes || echo no)"
  sb268_run env STUB_STATUS_OUT="interim 🚀 Reviewing" STUB_MAX=2 \
    STUB_GH_BODIES=$'<!-- devflow:stall-backstop-audit -->\nattempt one\n<!-- devflow:stall-backstop-audit -->\nattempt two'
  SB268_RC=$?
  assert_eq "#268 behavior: cap exhausted -> exit 1" "1" "$SB268_RC"
  assert_eq "#268 behavior: exhausted comment carries NO trigger phrase" "0" \
    "$(grep -cF '/devflow:implement ' "$SB268_POST" || true)"
  sb268_run env STUB_STATUS_RC=2
  assert_eq "#268 behavior: unreadable (no workpad) -> exit 1 + diagnostic comment" "1:yes" \
    "$?:$([ -f "$SB268_POST" ] && echo yes || echo no)"
  sb268_run env STUB_STATUS_OUT="interim 🚀 Reviewing" STUB_POST_FAIL=1
  SB268_RC=$?
  assert_eq "#268 behavior: dropped resume POST fails loud (exit 1, never a masked green)" "1" "$SB268_RC"
  # gh comment-read failure on interim: the attempt count is unknowable, so
  # the cap cannot be enforced — fail loud (unreadable class + diagnostic
  # comment), never an unbounded green resume loop.
  sb268_run env STUB_STATUS_OUT="interim 🚀 Reviewing" STUB_GH_FAIL=1
  SB268_RC=$?
  assert_eq "#268 behavior: gh comment-read failure -> attempt count unknowable, fail loud (exit 1, no trigger phrase)" "1:0" \
    "$SB268_RC:$(grep -cF '/devflow:implement ' "$SB268_POST" || true)"
  # #287 — that gh comment-read failure is now classified auth-failure (not
  # unreadable): the posted comment is the auth-specific body naming the
  # gh-api/transport/auth error, and no resume attempt was consumed.
  assert_eq "#287 behavior: gh comment-read failure -> auth-failure comment (names the auth error, not 'unreadable')" "yes" \
    "$(grep -qF 'gh-api/transport/auth error' "$SB268_POST" && grep -qF 'NO auto-resume attempt was consumed' "$SB268_POST" && echo yes || echo no)"
  # CRLF-bearing comment bodies still count (the count input is CR-stripped).
  sb268_run env STUB_STATUS_OUT="interim 🚀 Reviewing" STUB_MAX=2 \
    STUB_GH_BODIES=$'<!-- devflow:stall-backstop-audit -->\r\nattempt one\r'
  SB268_RC=$?
  assert_eq "#268 behavior: CRLF marker line still counts (resume as attempt 2 of 2)" "0:yes" \
    "$SB268_RC:$(grep -qF 'attempt 2 of 2' "$SB268_POST" && echo yes || echo no)"
  # Terminal path is lazy: the paginated comment fetch must never run.
  sb268_run env STUB_STATUS_OUT="terminal 👎 Blocked"
  SB268_RC=$?
  assert_eq "#268 behavior: terminal -> comment fetch skipped (gh never invoked)" "0:no" \
    "$SB268_RC:$([ -f "$SB268_DIR/gh-touched" ] && echo yes || echo no)"
  # Attempt boundary: one prior audit marker under cap 2 -> resume, body says 2 of 2.
  sb268_run env STUB_STATUS_OUT="interim 🚀 Reviewing" STUB_MAX=2 \
    STUB_GH_BODIES='<!-- devflow:stall-backstop-audit -->'
  SB268_RC=$?
  assert_eq "#268 behavior: one prior attempt under cap 2 -> resume, body names attempt 2 of 2" "0:yes" \
    "$SB268_RC:$(grep -qF 'attempt 2 of 2' "$SB268_POST" && echo yes || echo no)"
  # Quote-inflation guard: a QUOTED marker ("> <!-- ... -->") must not count.
  sb268_run env STUB_STATUS_OUT="interim 🚀 Reviewing" STUB_MAX=1 \
    STUB_GH_BODIES='> <!-- devflow:stall-backstop-audit -->'
  SB268_RC=$?
  assert_eq "#268 behavior: quoted marker does not inflate the attempt count (still resume under cap 1)" "0" "$SB268_RC"
  # Empty config-get output (hard-failure shape): safe-direction defaults hold.
  sb268_run env STUB_ENABLED= STUB_MAX= STUB_STATUS_OUT="terminal 🎉 Complete"
  SB268_RC=$?
  assert_eq "#268 behavior: empty config reads -> enabled + default cap (terminal still noop exit 0)" "0" "$SB268_RC"
  # mktemp failure: fail loud on EVERY decision arm (a resume comment that was
  # never posted must not read as green).
  sb268_run env STUB_STATUS_OUT="interim 🚀 Reviewing" STUB_MKTEMP_FAIL=1
  SB268_RC=$?
  assert_eq "#268 behavior: mktemp failure on a resume decision -> exit 1 (fail loud)" "1" "$SB268_RC"
  # No App token: the resume comment posts but cannot re-trigger -> fail loud.
  sb268_run env STUB_STATUS_OUT="interim 🚀 Reviewing" APP_TOKEN_PRESENT=false
  SB268_RC=$?
  assert_eq "#268 behavior: resume without the App token -> comment posted + exit 1 (inert resume never green)" "1:yes" \
    "$SB268_RC:$([ -f "$SB268_POST" ] && echo yes || echo no)"
  # Missing vendored dir: benign skip only when the claude step did not succeed;
  # on a successful run a vanished dir means the backstop is disarmed -> loud.
  SB268_EMPTY=$(mktemp -d)
  ( cd "$SB268_EMPTY" && CLAUDE_OUTCOME=success bash -e "$SB268_RUN" >/dev/null 2>&1 )
  assert_eq "#268 behavior: vendored dir missing on a successful claude step -> exit 1" "1" "$?"
  ( cd "$SB268_EMPTY" && CLAUDE_OUTCOME=failure bash -e "$SB268_RUN" >/dev/null 2>&1 )
  assert_eq "#268 behavior: vendored dir missing on a failed claude step -> benign exit 0" "0" "$?"
  rm -rf "$SB268_EMPTY"
  # Cap 0: detect-and-fail-loud only — straight to fail-exhausted, no trigger.
  sb268_run env STUB_STATUS_OUT="interim 🚀 Reviewing" STUB_MAX=0
  SB268_RC=$?
  assert_eq "#268 behavior: cap 0 -> immediate fail-exhausted exit 1, no trigger phrase" "1:0" \
    "$SB268_RC:$(grep -cF '/devflow:implement ' "$SB268_POST" || true)"
  # Non-integer cap: sanitized to the default 2 before it reaches the comments.
  sb268_run env STUB_STATUS_OUT="interim 🚀 Reviewing" STUB_MAX=banana
  SB268_RC=$?
  assert_eq "#268 behavior: non-integer cap -> default 2 in the resume body (never 'of banana')" "0:yes" \
    "$SB268_RC:$(grep -qF 'attempt 1 of 2' "$SB268_POST" && echo yes || echo no)"
  # Unreadable variants: exit-1 (unparseable/gh error) and rc-0-but-empty both
  # classify unreadable -> fail loud + diagnostic comment.
  sb268_run env STUB_STATUS_RC=1
  assert_eq "#268 behavior: status exit 1 (unparseable/gh error) -> exit 1 + diagnostic comment" "1:yes" \
    "$?:$([ -f "$SB268_POST" ] && echo yes || echo no)"
  sb268_run env STUB_STATUS_RC=0 STUB_STATUS_OUT=
  assert_eq "#268 behavior: status rc 0 with empty output -> defensively unreadable, exit 1" "1" "$?"
  # #287 — status exit 3 (gh-api/transport/auth failure) maps to the distinct
  # auth-failure class: fails loud (exit 1) with the auth-specific comment body,
  # NEVER labeled 'unreadable', and consumes NO resume attempt (no trigger
  # phrase). This is the core regression guard for the App-token-expiry fix — a
  # reintroduced exit-1 conflation would burn a resume attempt on a healthy
  # workpad. The gh comment fetch is skipped entirely on this path (auth-failure
  # is not 'interim'), so it also proves no attempt-count read is attempted.
  sb268_run env STUB_STATUS_RC=3
  SB268_RC=$?
  assert_eq "#287 behavior: status exit 3 -> auth-failure, fail loud exit 1 + comment" "1:yes" \
    "$SB268_RC:$([ -f "$SB268_POST" ] && echo yes || echo no)"
  assert_eq "#287 behavior: status exit 3 comment is the auth-failure body (not the unreadable one)" "yes" \
    "$(grep -qF 'gh-api/transport/auth error' "$SB268_POST" && grep -qF 'NO auto-resume attempt was consumed' "$SB268_POST" && echo yes || echo no)"
  assert_eq "#287 behavior: status exit 3 consumes no resume attempt (no trigger phrase, gh fetch skipped)" "1:0:no" \
    "$SB268_RC:$(grep -cF '/devflow:implement ' "$SB268_POST" || true):$([ -f "$SB268_DIR/gh-touched" ] && echo yes || echo no)"
  # Only the exact string "false" disables: an unrecognized value stays enabled
  # (the status read runs).
  sb268_run env STUB_ENABLED=False STUB_STATUS_OUT="terminal 🎉 Complete"
  SB268_RC=$?
  assert_eq "#268 behavior: unrecognized enabled value ('False') stays enabled (status read ran)" "0:yes" \
    "$SB268_RC:$([ -f "$SB268_DIR/status-touched" ] && echo yes || echo no)"
  rm -rf "$SB268_DIR"; rm -f "$SB268_RUN"
else
  printf '  SKIP  #268 behavior: python3+PyYAML unavailable — extraction test skipped (content pins above still ran)\n'
fi

# workpad.py status subcommand is registered (the backstop's status read path).
assert_eq "#266 workpad.py: status subcommand registered (func=cmd_status)" "yes" \
  "$(grep -q 'func=cmd_status' "$REPO_ROOT/scripts/workpad.py" && echo yes || echo no)"

# Behavioral: workpad.py status class derivation (mirrors the #222 gh-stub
# pattern at the top of this file). A glyph-set regression (dropping 👎 from the
# terminal tuple, or inverting terminal/interim) would misclassify a healthy
# terminal run as a stall — the CLASS token is fed verbatim to
# stall-backstop-decide.sh — so pin the mapping and the exit-code contract
# behaviorally, not just the argparse registration. RED pre-change: the `status`
# subcommand didn't exist, so the glyph assertions get argparse's empty stdout.
WP266_GHD="$(mktemp -d)"
cat > "$WP266_GHD/gh" <<'STUB'
#!/usr/bin/env bash
case "$*" in
  *"repo view"*) echo "acme/example-repo" ;;
  *"comments"*) if [ -n "${STUB_COMMENTS:-}" ]; then printf '%s\n' "$STUB_COMMENTS"; else echo '[]'; fi ;;
  *) echo '[]' ;;
esac
STUB
chmod +x "$WP266_GHD/gh"
WP266_PY="$REPO_ROOT/scripts/workpad.py"
WP266_OUT="$(PATH="$WP266_GHD:$PATH" STUB_COMMENTS='[{"id":1,"body":"<!-- devflow:workpad -->\n**Status:** 🎉 Complete"}]' python3 "$WP266_PY" status 5 2>/dev/null)"
assert_eq "#266 workpad.py status: Complete -> 'terminal 🎉 Complete'" "terminal 🎉 Complete" "$WP266_OUT"
WP266_OUT="$(PATH="$WP266_GHD:$PATH" STUB_COMMENTS='[{"id":1,"body":"<!-- devflow:workpad -->\n**Status:** 👎 Blocked"}]' python3 "$WP266_PY" status 5 2>/dev/null)"
assert_eq "#266 workpad.py status: Blocked -> 'terminal 👎 Blocked'" "terminal 👎 Blocked" "$WP266_OUT"
WP266_OUT="$(PATH="$WP266_GHD:$PATH" STUB_COMMENTS='[{"id":1,"body":"<!-- devflow:workpad -->\n**Status:** 🚀 Reviewing"}]' python3 "$WP266_PY" status 5 2>/dev/null)"
assert_eq "#266 workpad.py status: Reviewing -> 'interim 🚀 Reviewing'" "interim 🚀 Reviewing" "$WP266_OUT"
PATH="$WP266_GHD:$PATH" STUB_COMMENTS='[]' python3 "$WP266_PY" status 5 >/dev/null 2>&1
assert_eq "#266 workpad.py status: no workpad -> exit 2" "2" "$?"
PATH="$WP266_GHD:$PATH" STUB_COMMENTS='[{"id":1,"body":"<!-- devflow:workpad -->\nno status line here"}]' python3 "$WP266_PY" status 5 >/dev/null 2>&1
assert_eq "#266 workpad.py status: present but unreadable Status -> exit 1" "1" "$?"

# #287 — a gh-api/transport/auth failure (here a non-zero gh) must exit 3,
# kept DISTINCT from exit 1 (content-shape: unparseable/absent/unrecognized) and
# exit 2 (no workpad). Both cmd_status transport paths — the `gh api` comment
# fetch AND the `gh repo view` repo lookup — must return 3, so the stall backstop
# classifies it auth-failure and never mislabels a possibly-healthy workpad.
WP287_GHD="$(mktemp -d)"
cat > "$WP287_GHD/gh" <<'STUB'
#!/usr/bin/env bash
# repo view succeeds; the comment fetch fails (simulates a 401/transport error).
case "$*" in
  *"repo view"*) echo "acme/example-repo" ;;
  *) echo "HTTP 401: Bad credentials" >&2; exit 1 ;;
esac
STUB
chmod +x "$WP287_GHD/gh"
PATH="$WP287_GHD:$PATH" python3 "$WP266_PY" status 5 >/dev/null 2>&1
assert_eq "#287 workpad.py status: gh api comment-fetch failure -> exit 3 (auth/transport, not 1)" "3" "$?"
cat > "$WP287_GHD/gh" <<'STUB'
#!/usr/bin/env bash
echo "HTTP 401: Bad credentials" >&2; exit 1
STUB
chmod +x "$WP287_GHD/gh"
PATH="$WP287_GHD:$PATH" python3 "$WP266_PY" status 5 >/dev/null 2>&1
assert_eq "#287 workpad.py status: gh repo-view failure -> exit 3 (auth/transport)" "3" "$?"
# Regression guard: content-shape failures (no workpad, unparseable Status) must
# NOT drift to exit 3 — they stay 2 and 1 respectively under a healthy gh.
PATH="$WP266_GHD:$PATH" STUB_COMMENTS='[]' python3 "$WP266_PY" status 5 >/dev/null 2>&1
assert_eq "#287 workpad.py status: no workpad stays exit 2 (not 3) under healthy gh" "2" "$?"
PATH="$WP266_GHD:$PATH" STUB_COMMENTS='[{"id":1,"body":"<!-- devflow:workpad -->\nno status line here"}]' python3 "$WP266_PY" status 5 >/dev/null 2>&1
assert_eq "#287 workpad.py status: unparseable Status stays exit 1 (not 3) under healthy gh" "1" "$?"
# #287 — a gh api call that SUCCEEDS (rc 0) but returns an unparseable body (a
# dropped/truncated connection, which surfaces as json.JSONDecodeError in the
# comment fetch) is also a transport failure → exit 3, NOT the content-shape
# exit 1. This pins the docstring's "or that fetch returned an unparseable body"
# claim so a reclassification of the JSON-parse arm back to exit 1 goes RED.
cat > "$WP287_GHD/gh" <<'STUB'
#!/usr/bin/env bash
case "$*" in
  *"repo view"*) echo "acme/example-repo" ;;
  *) echo 'not json{' ;;   # rc 0, malformed body → JSONDecodeError in the fetch
esac
STUB
chmod +x "$WP287_GHD/gh"
PATH="$WP287_GHD:$PATH" python3 "$WP266_PY" status 5 >/dev/null 2>&1
assert_eq "#287 workpad.py status: gh success with unparseable body -> exit 3 (transport, not content-shape 1)" "3" "$?"
# #287 — a rc-0 gh response that PARSES but is not a JSON array (an error envelope
# like {"message":"Bad credentials"} — the realistic auth-at-exit-0 shape) must
# also exit 3, NOT crash into a bare exit 1 via AttributeError on `for c in items`.
# Pins the isinstance(items, list) guard so the exit-3 promise covers wrong-shape
# bodies, not only unparseable ones.
cat > "$WP287_GHD/gh" <<'STUB'
#!/usr/bin/env bash
case "$*" in
  *"repo view"*) echo "acme/example-repo" ;;
  *) echo '{"message":"Bad credentials"}' ;;   # rc 0, valid JSON, NOT a list
esac
STUB
chmod +x "$WP287_GHD/gh"
PATH="$WP287_GHD:$PATH" python3 "$WP266_PY" status 5 >/dev/null 2>&1
assert_eq "#287 workpad.py status: gh success with a non-list JSON body (error envelope) -> exit 3 (not AttributeError->1)" "3" "$?"
rm -rf "$WP287_GHD"
# #287 — the exit-code param defaults to 1, so a NON-status caller (cmd_id) on a
# gh transport failure exits EXACTLY 1, not 3 — locking the "every other caller
# unchanged" contract the diff claims (a regression flipping the default to 3
# would go RED here, where the pre-existing != 0 guards would not catch it).
WP287_IDGHD="$(mktemp -d)"
cat > "$WP287_IDGHD/gh" <<'STUB'
#!/usr/bin/env bash
echo "HTTP 401: Bad credentials" >&2; exit 1
STUB
chmod +x "$WP287_IDGHD/gh"
PATH="$WP287_IDGHD:$PATH" python3 "$WP266_PY" id 5 >/dev/null 2>&1
assert_eq "#287 workpad.py id: gh transport failure -> exit EXACTLY 1 (default code, non-status caller unchanged)" "1" "$?"
rm -rf "$WP287_IDGHD"

# #281 — a present-but-unrecognized Status word must fail closed (exit 1, distinct
# stderr diagnostic) exactly like the missing/empty cases above, instead of the
# pre-fix behavior of silently printing 'interim 🚀 <word>' at exit 0 (the stall
# backstop would then burn an auto-resume attempt on a workpad it cannot read).
WP281_STDERR=$(mktemp)
WP281_OUT="$(PATH="$WP266_GHD:$PATH" STUB_COMMENTS='[{"id":1,"body":"<!-- devflow:workpad -->\n**Status:** 🚀 Frobnicating"}]' python3 "$WP266_PY" status 5 2>"$WP281_STDERR")"
WP281_RC=$?
assert_eq "#281 workpad.py status: unrecognized word -> exit 1 (not 0)" "1" "$WP281_RC"
assert_eq "#281 workpad.py status: unrecognized word -> no stdout printed" "" "$WP281_OUT"
assert_eq "#281 workpad.py status: unrecognized word -> stderr names the word" "yes" \
  "$(grep -q 'Frobnicating' "$WP281_STDERR" && echo yes || echo no)"
rm -f "$WP281_STDERR"
PATH="$WP266_GHD:$PATH" STUB_COMMENTS='[{"id":1,"body":"<!-- devflow:workpad -->\n**Status:** FROBNICATING"}]' python3 "$WP266_PY" status 5 >/dev/null 2>&1
assert_eq "#281 workpad.py status: unrecognized word, mixed case -> exit 1" "1" "$?"

# #281 — a word that merely STARTS WITH the terminal words 'complete'/'blocked' must
# still be rejected (exit 1), not silently accepted via _status_glyph's prefix match.
# Recognition must be exact-match on the terminal words, since _status_glyph's own
# startswith('complete'/'blocked') is intentionally loose for its write-path callers.
PATH="$WP266_GHD:$PATH" STUB_COMMENTS='[{"id":1,"body":"<!-- devflow:workpad -->\n**Status:** 🎉 Completely wrong word"}]' python3 "$WP266_PY" status 5 >/dev/null 2>&1
assert_eq "#281 workpad.py status: prefix-adjacent 'Completely wrong word' -> exit 1 (not silently terminal)" "1" "$?"
PATH="$WP266_GHD:$PATH" STUB_COMMENTS='[{"id":1,"body":"<!-- devflow:workpad -->\n**Status:** 👎 Blockeddependency on X"}]' python3 "$WP266_PY" status 5 >/dev/null 2>&1
assert_eq "#281 workpad.py status: prefix-adjacent 'Blockeddependency on X' -> exit 1 (not silently terminal)" "1" "$?"

# #281 — every canonical in-progress word not already exercised above must still
# resolve at exit 0 with no regression to the healthy paths.
for WP281_WORD in Setup Discovering Reproducing Planning Implementing Documenting; do
  WP281_OUT="$(PATH="$WP266_GHD:$PATH" STUB_COMMENTS="[{\"id\":1,\"body\":\"<!-- devflow:workpad -->\n**Status:** 🚀 $WP281_WORD\"}]" python3 "$WP266_PY" status 5 2>/dev/null)"
  assert_eq "#281 workpad.py status: $WP281_WORD -> 'interim 🚀 $WP281_WORD'" "interim 🚀 $WP281_WORD" "$WP281_OUT"
done

# #281 — regression guard: empty Status value (present line, no word) still exits
# non-zero exactly as before (unchanged path, not the new unrecognized-word path).
PATH="$WP266_GHD:$PATH" STUB_COMMENTS='[{"id":1,"body":"<!-- devflow:workpad -->\n**Status:**    "}]' python3 "$WP266_PY" status 5 >/dev/null 2>&1
assert_eq "#281 workpad.py status: empty Status value -> exit 1 (regression, unchanged)" "1" "$?"

# #281 — single-source guard: the recognized-word set must be derived from
# _STATUS_TO_PROGRESS_PHASE, not a second hardcoded list. Prove it by adding a
# synthetic key to that dict at runtime and confirming the synthetic word becomes
# recognized (exit 0) — if recognition were a separate hardcoded list, this
# monkeypatch would have no effect and the word would still be rejected.
WP281_SINGLE_SOURCE="$(PATH="$WP266_GHD:$PATH" STUB_COMMENTS='[{"id":1,"body":"<!-- devflow:workpad -->\n**Status:** 🚀 Frobnicating"}]' python3 -c "
import sys
sys.path.insert(0, '$REPO_ROOT/scripts')
sys.argv = ['workpad.py', 'status', '5']
import workpad
workpad._STATUS_TO_PROGRESS_PHASE['frobnicating'] = 'Implement'
try:
    workpad.main()
except SystemExit as e:
    print('exit', e.code)
" 2>/dev/null)"
assert_eq "#281 workpad.py status: recognized-word set single-sourced from _STATUS_TO_PROGRESS_PHASE" "interim 🚀 Frobnicating" "$WP281_SINGLE_SOURCE"
rm -rf "$WP266_GHD"

# ── issue #284: portability wave 3 — rc-capture guard recipes migrated off the ──
# inline-bash cross-statement-variable-stripping hazard. A runner whose inline `bash -c`
# marshaling strips a variable assigned in one statement and read in a LATER statement
# (Copilot CLI; expected on Cursor / Codex CLI / Gemini CLI) left the old
# `VAR=$(…); VAR_RC=$?` recipes' captured rc empty, so their fail-closed checks and DISTINCT
# breadcrumbs silently no-op'd. The migration replaces each with a single-statement `if !`
# (or an `elif [ "$?" … ]` for a 3-way) that reads the command's OWN exit status inline.
echo "#284 portability wave 3: rc-capture guard migration"
# (1) ABSENCE (AC5): the banned recipe is a line carrying a command substitution `=$(` AND
# an uppercase `<IDENT>_RC=$?` capture (or a `<subst>); rc=$?` lowercase capture). This is
# precisely the AC1 target and does NOT match the intentionally-exempt `cmd; rc=$?` survivors
# (review's #216-pinned dirty-tree cmp_rc/gmrc, init's grep rc), whose rc line carries no
# `=$(`. Assert ZERO such lines in every migrated skill body — a reintroduced
# capture-then-discriminate recipe turns this RED. (The grep targets `"$1"`, carrying no
# `_SKILL`/echo, so the #157 raw-guard scanner does not match this helper's body.)
count_284_subst_rc_recipe() {  # file -> count of the banned command-substitution-then-rc recipe
  # `="?\$\(` matches BOTH the unquoted `VAR=$(…)` and the quoted `VAR="$(…)"` assignment —
  # the removed efficiency-trace recipes (`TRACE="$(…)"; TRACE_RC=$?` / `TELEM="$(…)"; T_RC=$?`)
  # were the QUOTED form, whose bytes are `="$(` (no `=$(` substring), so a bare `=\$\(` anchor
  # would read 0 on their reintroduction and leave AC5 vacuous for exactly two removed sites
  # (#284 shadow review). The optional `"` closes that gap without matching a single-quoted
  # `='$('` (which performs no substitution and is not a real recipe).
  grep -cE '="?\$\(.*[A-Z_]+_RC=\$\?|="?\$\(.*; *rc=\$\?' "$1" || true
}
assert_eq "#284 absence: no VAR=\$(…);VAR_RC=\$? recipe in review-and-fix SKILL" "0" "$(count_284_subst_rc_recipe "$ST_RAF")"
assert_eq "#284 absence: no VAR=\$(…);VAR_RC=\$? recipe in review SKILL" "0" "$(count_284_subst_rc_recipe "$ST_REV")"
assert_eq "#284 absence: no VAR=\$(…);VAR_RC=\$? recipe in receiving-code-review SKILL" "0" "$(count_284_subst_rc_recipe "$ST_RCV")"
assert_eq "#284 absence: no VAR=\$(…);VAR_RC=\$? recipe in implement-skill bundle (phase-4 doc gate)" "0" "$(count_284_subst_rc_recipe "$DEF_SKILL")"
# Mutation proof that the absence detector is not vacuous: a temp file carrying the banned
# recipe must read 1 (RED), and a migrated `if !` form must read 0 (GREEN).
P284_PROBE="$(probe_tmp '#284 absence detector proof')"
printf '%s\n' 'FOO=$(somecmd .k default); FOO_RC=$?' > "$P284_PROBE"
assert_eq "#284 absence detector: a reintroduced VAR=\$(…);VAR_RC=\$? recipe reads 1 (RED, not vacuous)" "1" "$(count_284_subst_rc_recipe "$P284_PROBE")"
printf '%s\n' 'if ! FOO=$(somecmd .k default); then FOO=default; fi' > "$P284_PROBE"
assert_eq "#284 absence detector: the migrated if!-form reads 0 (GREEN)" "0" "$(count_284_subst_rc_recipe "$P284_PROBE")"
# Quoted command-substitution reintroduction (the removed TRACE/TELEM shape: `VAR="$(…)"; VAR_RC=$?`)
# must ALSO read 1 (RED) — a bare `=\$\(` anchor would miss it, leaving AC5 vacuous for those two
# sites; and the migrated quoted `if ! VAR="$(…)"` form must read 0 (GREEN, no false positive).
printf '%s\n' 'TRACE="$(efficiency-trace.sh --mode trace)"; TRACE_RC=$?' > "$P284_PROBE"
assert_eq "#284 absence detector: a reintroduced QUOTED VAR=\"\$(…)\";VAR_RC=\$? recipe reads 1 (RED, not vacuous)" "1" "$(count_284_subst_rc_recipe "$P284_PROBE")"
printf '%s\n' 'if ! TRACE="$(efficiency-trace.sh --mode trace)"; then TRACE=""; fi' > "$P284_PROBE"
assert_eq "#284 absence detector: the migrated QUOTED if!-form reads 0 (GREEN)" "0" "$(count_284_subst_rc_recipe "$P284_PROBE")"
rm -f "$P284_PROBE"
# (1b) TWO-LINE absence (#284 shadow review, AC5 completeness): the single-line detector
# above is line-oriented, so the SAME cross-statement hazard written across two physical
# lines — `VAR=$(…)` on one line, `VAR_RC=$?` (or `; rc=$?`) on the next — would slip past
# it. That split form is exactly the reintroduction AC5 must turn RED. A portable POSIX awk
# pass (no `grep -P`) flags a command-substitution assignment whose rc capture lands on a
# later line — both the simple two-line form AND the trailing-rc-after-backslash-continuation
# form the shadow review flagged (per-shape detail in the function body). It reads 0 on every
# migrated body today (the recipes are gone) and does NOT match the exempt `cmd; rc=$?`
# survivors (their rc line carries no `=$(` and no backslash-continued `=$(` precedes it).
count_284_twoline_rc_recipe() {  # file -> count of the banned recipe split across lines (2-line + line-continuation)
  # Two shapes, both the historical recipe this PR removed:
  #   (a) two-line-at-start:   VAR=$(cmd)              (b) trailing-after-continuation: VAR=$(printf x \
  #                            VAR_RC=$?                                                   | cmd); VAR_RC=$?
  # (a) is caught by the prev-line rule; (b) by a stateful `open` flag that tracks a command-
  # substitution assignment continued to a later line until its `); VAR_RC=$?` close. A line
  # continues when it ends with a backslash OR with a pipe/operator (`|`, `&&`, `||`) — bash
  # continues all of these without a backslash, and the historical recipe this PR removed
  # literally PIPED `printf … | extractor`, so the pipe-continuation form is at least as likely
  # a reintroduction as the backslash one. Neither rule matches the exempt same-line
  # `cmd; rc=$?` survivors (cmp_rc/gmrc/init grep) — their rc line carries no `=$(`, does not
  # start with the rc token, and is not preceded by a continued `=$(` assignment.
  awk '
    {
      if (open && $0 ~ /([A-Z_]+_RC|rc)=\$\?/) { c++; open=0 }
      else if (open && $0 !~ /(\\|&&|\|)[[:space:]]*$/) { open=0 }
      if ($0 ~ /="?\$\(/ && $0 ~ /(\\|&&|\|)[[:space:]]*$/) { open=1 }
      if (prev ~ /="?\$\(/ && $0 ~ /^[[:space:]]*([A-Z_]+_RC|rc)=\$\?/) { c++ }
      prev = $0
    }
    END { print c+0 }
  ' "$1"
}
assert_eq "#284 absence(2-line): no split VAR=\$(…)/VAR_RC=\$? recipe in review-and-fix SKILL" "0" "$(count_284_twoline_rc_recipe "$ST_RAF")"
assert_eq "#284 absence(2-line): no split VAR=\$(…)/VAR_RC=\$? recipe in review SKILL" "0" "$(count_284_twoline_rc_recipe "$ST_REV")"
assert_eq "#284 absence(2-line): no split VAR=\$(…)/VAR_RC=\$? recipe in receiving-code-review SKILL" "0" "$(count_284_twoline_rc_recipe "$ST_RCV")"
assert_eq "#284 absence(2-line): no split VAR=\$(…)/VAR_RC=\$? recipe in implement-skill bundle" "0" "$(count_284_twoline_rc_recipe "$DEF_SKILL")"
# Mutation proof the two-line detector is not vacuous: the split recipe reads 1 (RED), the
# migrated single-statement form reads 0 (GREEN).
P284_2L="$(probe_tmp '#284 two-line absence detector proof')"
printf '%s\n' 'FOO=$(somecmd .k default)' 'FOO_RC=$?' > "$P284_2L"
assert_eq "#284 absence(2-line) detector: a split VAR=\$(…)/VAR_RC=\$? recipe reads 1 (RED, not vacuous)" "1" "$(count_284_twoline_rc_recipe "$P284_2L")"
printf '%s\n' 'if ! FOO=$(somecmd .k default); then FOO=default; fi' > "$P284_2L"
assert_eq "#284 absence(2-line) detector: the migrated if!-form reads 0 (GREEN)" "0" "$(count_284_twoline_rc_recipe "$P284_2L")"
# Mutation proof for the trailing-after-line-continuation shape (the exact historical form
# this PR removed: a piped substitution continued with a backslash, rc captured after the
# close). This is the shape the shadow review flagged as slipping past a naive 2-line detector.
printf '%s\n' 'DOC_NEEDED_PATHS=$(printf '"'"'%s'"'"' "$ISSUE_BODY" \' '  | ./extract-doc-needed-paths.sh); HELPER_RC=$?' > "$P284_2L"
assert_eq "#284 absence(2-line) detector: a trailing-rc-after-backslash-continuation recipe reads 1 (RED, not vacuous)" "1" "$(count_284_twoline_rc_recipe "$P284_2L")"
# The historical recipe PIPED printf into the extractor; a pipe-continued reintroduction (pipe
# at line end, NO backslash — bash continues it) must also read 1. This is the exact form the
# removed recipe used, so it is the most realistic reintroduction shape.
printf '%s\n' 'DOC_NEEDED_PATHS=$(printf '"'"'%s'"'"' "$ISSUE_BODY" |' '  ./extract-doc-needed-paths.sh); HELPER_RC=$?' > "$P284_2L"
assert_eq "#284 absence(2-line) detector: a trailing-rc-after-PIPE-continuation recipe reads 1 (RED, not vacuous)" "1" "$(count_284_twoline_rc_recipe "$P284_2L")"
# And the migrated fixed-temp-file form (multi-statement, no rc capture) reads 0 (GREEN):
printf '%s\n' 'if ! gh issue view $N --json body > /tmp/b.txt \' '   && ! gh issue view $N --json body > /tmp/b.txt; then :; fi' > "$P284_2L"
assert_eq "#284 absence(2-line) detector: the migrated temp-file form reads 0 (GREEN)" "0" "$(count_284_twoline_rc_recipe "$P284_2L")"
rm -f "$P284_2L"
# The extractor-side captured-rc token (HELPER_RC) must be GONE too — the shadow flagged that
# only GH_RC/DIFF_RC had absence pins, leaving the extractor value-hop's rc capture unpinned.
assert_eq "#284 shadow-fix: Phase 4.1 no longer carries the old HELPER_RC extractor-rc capture" \
  "0" "$(pin_count 'HELPER_RC=$?' "$IMPL_SKILL")"
# The efficiency-trace `--mode record` gates in BOTH review engines were migrated from the
# `cmd > "$RECORD"; RECORD_RC=$? / R_RC=$?` capture-then-discriminate form to a single-statement
# `if cmd > "$RECORD"; then …` — but that redirect-capture is NOT a command substitution, so the
# `="?\$\(`-anchored absence detectors above cannot see its reintroduction (#284 shadow review,
# 2nd pass). Pin the removed rc tokens directly so a straight revert of either record-write block
# — which would re-inert the `[ "$RECORD_RC" -ne 0 ]` check on a value-stripping runner — turns
# the suite RED; the positive `; then`-form pins below back them so a revert fails two ways.
assert_eq "#284 shadow-fix: review-and-fix record gate no longer carries the old RECORD_RC capture" \
  "0" "$(pin_count 'RECORD_RC=$?' "$ST_RAF")"
assert_eq "#284 shadow-fix: review record gate no longer carries the old R_RC capture" \
