{ printf '%s\n' '```bash' 'gh issue comment 5 -b "Doesn'"'"'t matter: $(.devflow/vendor/devflow/scripts/apply-labels.sh 5 DevFlow 2>&1)"' '```'; } > "$E363/i-fo-apos-capture.md"
