{ printf '%s\n' '```bash' "X=\$(echo \"\$L\" | tr ',' '\\n' | paste -sd, -)" '```'; } > "$E363/i-paste.md"
assert_eq "#455 ungranted-head pin goes RED on a fence that uses paste (anti-vacuity)" "1" \
